/**
 * WebSocket Configuration
 * Socket.io entegrasyonu için yapılandırma
 */

import { Server as HttpServer } from 'http';
import { Server as SocketIOServer, Socket } from 'socket.io';
import { authenticateSocket } from '../middleware/socketAuth.middleware';
import logger from '../utils/logger';

let io: SocketIOServer | null = null;

/**
 * WebSocket server'ı başlat
 */
export const initWebSocket = (httpServer: HttpServer): SocketIOServer => {
  if (io) {
    return io;
  }

  io = new SocketIOServer(httpServer, {
    cors: {
      origin: process.env.CLIENT_URL || 'http://localhost:3000',
      methods: ['GET', 'POST'],
      credentials: true,
    },
    path: '/socket.io',
  });

  // Authentication middleware
  io.use(authenticateSocket);

  interface AuthenticatedSocket extends Socket {
    user?: {
      id?: string;
      _id?: string;
      role?: string;
    };
  }

  // Connection handler
  io.on('connection', (socket: Socket) => {
    const authSocket = socket as AuthenticatedSocket;
    const userId = authSocket.user?.id || authSocket.user?._id;
    const userRole = authSocket.user?.role;

    logger.info(`WebSocket: Kullanıcı bağlandı`, { userId, userRole, socketId: socket.id });

    // Kullanıcıyı kendi room'una ekle
    if (userId) {
      socket.join(`user:${userId}`);
      socket.join(`role:${userRole}`);
    }

    // Collaborative editing için room'lar
    socket.on('join:project', (projectId: string) => {
      socket.join(`project:${projectId}`);
      logger.debug(`WebSocket: Kullanıcı proje room'una katıldı`, { userId, projectId });
    });

    socket.on('leave:project', (projectId: string) => {
      socket.leave(`project:${projectId}`);
      logger.debug(`WebSocket: Kullanıcı proje room'undan ayrıldı`, { userId, projectId });
    });

    // Collaborative editing events
    socket.on('project:edit', (data: { projectId: string; changes: any }) => {
      // Diğer kullanıcılara broadcast et
      socket.to(`project:${data.projectId}`).emit('project:update', {
        userId,
        changes: data.changes,
        timestamp: new Date().toISOString(),
      });
    });

    // Disconnect handler
    socket.on('disconnect', () => {
      logger.info(`WebSocket: Kullanıcı bağlantısı kesildi`, { userId, socketId: socket.id });
    });
  });

  logger.info('✅ WebSocket server başlatıldı');
  return io;
};

/**
 * WebSocket server instance'ını al
 */
export const getWebSocketServer = (): SocketIOServer | null => {
  return io;
};

/**
 * Belirli bir role mesaj gönder
 */
export const sendToRole = (role: string, event: string, data: any) => {
  if (io) {
    io.to(`role:${role}`).emit(event, data);
  }
};

/**
 * Belirli bir kullanıcıya mesaj gönder
 */
export const sendToUser = (userId: string, event: string, data: any) => {
  if (io) {
    io.to(`user:${userId}`).emit(event, data);
  }
};

/**
 * Tüm kullanıcılara broadcast et
 */
export const broadcast = (event: string, data: any) => {
  if (io) {
    io.emit(event, data);
  }
};

/**
 * Belirli bir room'a mesaj gönder
 */
export const sendToRoom = (room: string, event: string, data: any) => {
  if (io) {
    io.to(room).emit(event, data);
  }
};

import type { Request, Response } from 'express';
import mongoose, { Model } from 'mongoose';
import { Client, Equipment, Maintenance, Project, Task, User } from '../models';
import logger from '../utils/logger';
import { optimizeAggregation } from '../utils/aggregationOptimizer';

const parseDate = (raw: unknown): Date | null => {
  if (typeof raw !== 'string' || !raw) return null;
  const d = new Date(raw);
  if (Number.isNaN(d.getTime())) return null;
  return d;
};

const clampRange = (start: Date, end: Date, maxDays = 365) => {
  const ms = end.getTime() - start.getTime();
  const maxMs = maxDays * 24 * 60 * 60 * 1000;
  if (ms <= 0) return { start, end: new Date(start.getTime() + 24 * 60 * 60 * 1000) };
  if (ms > maxMs) return { start, end: new Date(start.getTime() + maxMs) };
  return { start, end };
};

const toDayKey = (d: Date) => new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()));

const collectionName = (model: Model<any>, fallback: string) => {
  return model?.collection?.name || fallback;
};

export const getAnalyticsDashboard = async (req: Request, res: Response) => {
  try {
    const endRaw = parseDate(req.query.to);
    const startRaw = parseDate(req.query.from);

    const end = endRaw || new Date();
    const startDefault = new Date(end);
    startDefault.setUTCMonth(startDefault.getUTCMonth() - 6);
    const start = startRaw || startDefault;

    const { start: rangeStart, end: rangeEnd } = clampRange(start, end, 365);
    const rangeMs = rangeEnd.getTime() - rangeStart.getTime();
    const prevStart = new Date(rangeStart.getTime() - rangeMs);
    const prevEnd = new Date(rangeStart.getTime());

    // Ensure DB is connected (should already be guarded by requireDbConnection)
    const dbConnected = mongoose.connection.readyState === 1;
    if (!dbConnected) {
      return res.status(503).json({ success: false, message: 'Database not connected' });
    }

    // --- Projects ---
    const projectMatch = { startDate: { $gte: rangeStart, $lte: rangeEnd } };

    // Optimize edilmiş aggregation pipeline'ları
    const projectByStatusPipeline = optimizeAggregation([
      { $match: projectMatch },
      { $group: { _id: '$status', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
    ]);

    const projectByStatus = await Project.aggregate(projectByStatusPipeline, { allowDiskUse: true });

    const projectTrendPipeline = optimizeAggregation([
      { $match: projectMatch },
      {
        $group: {
          _id: { $dateToString: { format: '%Y-%m', date: '$startDate' } },
          count: { $sum: 1 },
        },
      },
      { $sort: { _id: 1 } },
    ]);

    const projectTrend = await Project.aggregate(projectTrendPipeline, { allowDiskUse: true });

    // $lookup'tan önce $limit kullanarak performansı artır
    const topClientsPipeline = optimizeAggregation([
      { $match: projectMatch },
      { $group: { _id: '$client', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
      { $limit: 8 }, // $lookup'tan önce limit uygula
      {
        $lookup: {
          from: collectionName(Client, 'clients'),
          localField: '_id',
          foreignField: '_id',
          as: 'client',
        },
      },
      { $unwind: { path: '$client', preserveNullAndEmptyArrays: true } },
      { $project: { clientId: '$_id', count: 1, name: '$client.name' } },
    ]);

    const topClients = await Project.aggregate(topClientsPipeline, { allowDiskUse: true });

    // Avg project duration (days) - optimize edilmiş
    const avgProjectDurationPipeline = optimizeAggregation([
      { $match: projectMatch },
      {
        $project: {
          durationDays: {
            $divide: [
              { $subtract: [{ $ifNull: ['$endDate', '$startDate'] }, '$startDate'] },
              1000 * 60 * 60 * 24,
            ],
          },
        },
      },
      { $group: { _id: null, avg: { $avg: '$durationDays' } } },
    ]);

    const avgProjectDurationAgg = await Project.aggregate(avgProjectDurationPipeline, { allowDiskUse: true });
    const avgProjectDurationDays = avgProjectDurationAgg?.[0]?.avg ? Number(avgProjectDurationAgg[0].avg) : 0;

    // --- Tasks ---
    const taskMatch = { createdAt: { $gte: rangeStart, $lte: rangeEnd } };

    const tasksByStatusPipeline = optimizeAggregation([
      { $match: taskMatch },
      { $group: { _id: '$status', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
    ]);
    const tasksByStatus = await Task.aggregate(tasksByStatusPipeline, { allowDiskUse: true });

    const tasksByPriorityPipeline = optimizeAggregation([
      { $match: taskMatch },
      { $group: { _id: '$priority', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
    ]);
    const tasksByPriority = await Task.aggregate(tasksByPriorityPipeline, { allowDiskUse: true });

    // $lookup'tan önce $limit kullanarak performansı artır
    const tasksByAssigneePipeline = optimizeAggregation([
      { $match: taskMatch },
      { $group: { _id: '$assignedTo', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
      { $limit: 8 }, // $lookup'tan önce limit uygula
      {
        $lookup: {
          from: collectionName(User, 'users'),
          localField: '_id',
          foreignField: '_id',
          as: 'user',
        },
      },
      { $unwind: { path: '$user', preserveNullAndEmptyArrays: true } },
      { $project: { userId: '$_id', count: 1, name: '$user.name', email: '$user.email' } },
    ]);
    const tasksByAssignee = await Task.aggregate(tasksByAssigneePipeline, { allowDiskUse: true });

    // Tasks completed per day (trend) - optimize edilmiş
    const tasksCompletedTrendPipeline = optimizeAggregation([
      {
        $match: {
          completedDate: { $gte: rangeStart, $lte: rangeEnd },
          status: 'COMPLETED',
        },
      },
      {
        $group: {
          _id: { $dateToString: { format: '%Y-%m-%d', date: '$completedDate' } },
          count: { $sum: 1 },
        },
      },
      { $sort: { _id: 1 } },
    ]);
    const tasksCompletedTrend = await Task.aggregate(tasksCompletedTrendPipeline, { allowDiskUse: true });

    // Basic forecasting: next 7 days based on last 14-day average of completed tasks
    const forecastWindowEnd = toDayKey(rangeEnd);
    const forecastWindowStart = new Date(forecastWindowEnd.getTime() - 14 * 24 * 60 * 60 * 1000);
    const last14 = await Task.countDocuments({
      completedDate: { $gte: forecastWindowStart, $lte: forecastWindowEnd },
      status: 'COMPLETED',
    });
    const avgPerDay = last14 / 14;
    const forecastNext7 = Array.from({ length: 7 }).map((_, i) => {
      const day = new Date(forecastWindowEnd.getTime() + (i + 1) * 24 * 60 * 60 * 1000);
      return { day: day.toISOString().slice(0, 10), expectedCompleted: Math.round(avgPerDay) };
    });

    // --- Equipment ---
    const equipmentByStatusPipeline = optimizeAggregation([
      { $group: { _id: '$status', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
    ]);
    const equipmentByStatus = await Equipment.aggregate(equipmentByStatusPipeline);

    const equipmentByTypePipeline = optimizeAggregation([
      { $group: { _id: '$type', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
    ]);
    const equipmentByType = await Equipment.aggregate(equipmentByTypePipeline);

    // $lookup'tan önce $limit kullanarak performansı artır
    const inUseByProjectPipeline = optimizeAggregation([
      { $match: { status: 'IN_USE', currentProject: { $exists: true, $ne: null } } },
      { $group: { _id: '$currentProject', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
      { $limit: 8 }, // $lookup'tan önce limit uygula
      {
        $lookup: {
          from: collectionName(Project, 'projects'),
          localField: '_id',
          foreignField: '_id',
          as: 'project',
        },
      },
      { $unwind: { path: '$project', preserveNullAndEmptyArrays: true } },
      { $project: { projectId: '$_id', count: 1, name: '$project.name', status: '$project.status' } },
    ]);
    const inUseByProject = await Equipment.aggregate(inUseByProjectPipeline, { allowDiskUse: true });

    // --- Maintenance ---
    const maintenanceMatch = { scheduledDate: { $gte: rangeStart, $lte: rangeEnd } };

    const maintenanceByStatusPipeline = optimizeAggregation([
      { $match: maintenanceMatch },
      { $group: { _id: '$status', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
    ]);
    const maintenanceByStatus = await Maintenance.aggregate(maintenanceByStatusPipeline, { allowDiskUse: true });

    const maintenanceByTypePipeline = optimizeAggregation([
      { $match: maintenanceMatch },
      { $group: { _id: '$type', count: { $sum: 1 } } },
      { $sort: { count: -1 } },
    ]);
    const maintenanceByType = await Maintenance.aggregate(maintenanceByTypePipeline, { allowDiskUse: true });

    const maintenanceCostPipeline = optimizeAggregation([
      { $match: maintenanceMatch },
      { $group: { _id: null, total: { $sum: { $ifNull: ['$cost', 0] } }, avg: { $avg: '$cost' } } },
    ]);
    const maintenanceCostAgg = await Maintenance.aggregate(maintenanceCostPipeline, { allowDiskUse: true });
    const maintenanceCostTotal = maintenanceCostAgg?.[0]?.total ? Number(maintenanceCostAgg[0].total) : 0;
    const maintenanceCostAvg = maintenanceCostAgg?.[0]?.avg ? Number(maintenanceCostAgg[0].avg) : 0;
    const upcomingMaintenanceCount = await Maintenance.countDocuments({
      scheduledDate: { $gte: new Date(), $lte: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000) },
      status: { $in: ['SCHEDULED', 'IN_PROGRESS'] },
    });

    // --- Comparison (previous range) ---
    const prevProjects = await Project.countDocuments({ startDate: { $gte: prevStart, $lte: prevEnd } });
    const prevTasksCreated = await Task.countDocuments({ createdAt: { $gte: prevStart, $lte: prevEnd } });
    const prevTasksCompleted = await Task.countDocuments({ completedDate: { $gte: prevStart, $lte: prevEnd }, status: 'COMPLETED' });
    const curProjects = await Project.countDocuments({ startDate: { $gte: rangeStart, $lte: rangeEnd } });
    const curTasksCreated = await Task.countDocuments({ createdAt: { $gte: rangeStart, $lte: rangeEnd } });
    const curTasksCompleted = await Task.countDocuments({ completedDate: { $gte: rangeStart, $lte: rangeEnd }, status: 'COMPLETED' });

    const pct = (cur: number, prev: number) => {
      if (!prev) return cur ? 100 : 0;
      return ((cur - prev) / prev) * 100;
    };

    return res.status(200).json({
      success: true,
      range: {
        from: rangeStart.toISOString(),
        to: rangeEnd.toISOString(),
        prevFrom: prevStart.toISOString(),
        prevTo: prevEnd.toISOString(),
      },
      comparison: {
        projects: { current: curProjects, previous: prevProjects, changePct: pct(curProjects, prevProjects) },
        tasksCreated: { current: curTasksCreated, previous: prevTasksCreated, changePct: pct(curTasksCreated, prevTasksCreated) },
        tasksCompleted: { current: curTasksCompleted, previous: prevTasksCompleted, changePct: pct(curTasksCompleted, prevTasksCompleted) },
      },
      projects: {
        byStatus: projectByStatus.map((x: { _id: string; count: number }) => ({ status: x._id, count: x.count })),
        trendByMonth: projectTrend.map((x: { _id: string; count: number }) => ({ month: x._id, count: x.count })),
        topClients,
        avgDurationDays: avgProjectDurationDays,
      },
      tasks: {
        byStatus: tasksByStatus.map((x: { _id: string; count: number }) => ({ status: x._id, count: x.count })),
        byPriority: tasksByPriority.map((x: { _id: string; count: number }) => ({ priority: x._id, count: x.count })),
        byAssignee: tasksByAssignee,
        completedTrendByDay: tasksCompletedTrend.map((x: { _id: string; count: number }) => ({ day: x._id, count: x.count })),
        forecastNext7Days: forecastNext7,
      },
      equipment: {
        byStatus: equipmentByStatus.map((x: { _id: string; count: number }) => ({ status: x._id, count: x.count })),
        byType: equipmentByType.map((x: { _id: string; count: number }) => ({ type: x._id, count: x.count })),
        inUseByProject,
      },
      maintenance: {
        byStatus: maintenanceByStatus.map((x: { _id: string; count: number }) => ({ status: x._id, count: x.count })),
        byType: maintenanceByType.map((x: { _id: string; count: number }) => ({ type: x._id, count: x.count })),
        cost: { total: maintenanceCostTotal, avg: maintenanceCostAvg },
        upcoming14d: upcomingMaintenanceCount,
      },
    });
  } catch (error) {
    logger.error('Analytics dashboard hatası:', error);
    return res.status(500).json({ success: false, message: 'Analytics verileri alınamadı' });
  }
};

import { Request, Response } from 'express';
import { getAuditLogs } from '../utils/auditLogger';
import logger from '../utils/logger';

// Aktivite loglarını getir
export const getAuditLogsController = async (req: Request, res: Response) => {
  try {
    const {
      user,
      resource,
      resourceId,
      action,
      startDate,
      endDate,
      page = 1,
      limit = 50,
    } = req.query;

    const filters: any = {};

    if (user) {
      filters.user = user as string;
    }

    if (resource) {
      filters.resource = resource as string;
    }

    if (resourceId) {
      filters.resourceId = resourceId as string;
    }

    if (action) {
      filters.action = action as string;
    }

    if (startDate) {
      filters.startDate = new Date(startDate as string);
    }

    if (endDate) {
      filters.endDate = new Date(endDate as string);
    }

    const result = await getAuditLogs({
      ...filters,
      page: parseInt(page as string, 10),
      limit: parseInt(limit as string, 10),
    });

    res.status(200).json({
      success: true,
      ...result,
    });
  } catch (error) {
    logger.error('Aktivite logları getirme hatası:', error);
    res.status(500).json({
      success: false,
      message: 'Aktivite logları getirilirken bir hata oluştu',
    });
  }
};

// Belirli bir kaynağın aktivite geçmişini getir
export const getResourceAuditHistory = async (req: Request, res: Response) => {
  try {
    const { resource, resourceId } = req.params;
    const { page = 1, limit = 50 } = req.query;

    const result = await getAuditLogs({
      resource: resource as any,
      resourceId: resourceId,
      page: parseInt(page as string, 10),
      limit: parseInt(limit as string, 10),
    });

    res.status(200).json({
      success: true,
      ...result,
    });
  } catch (error) {
    logger.error('Kaynak aktivite geçmişi getirme hatası:', error);
    res.status(500).json({
      success: false,
      message: 'Aktivite geçmişi getirilirken bir hata oluştu',
    });
  }
};

import { Request, Response } from 'express';
import { Equipment, Project, Task, User, Maintenance } from '../models';
import mongoose from 'mongoose';
import logger from '../utils/logger';
import { logAction } from '../utils/auditLogger';

// Toplu silme
export const bulkDelete = async (req: Request, res: Response) => {
  try {
    const { resource, ids } = req.body;

    if (!resource || !Array.isArray(ids) || ids.length === 0) {
      return res.status(400).json({
        success: false,
        message: 'Kaynak tipi ve ID listesi gereklidir',
      });
    }

    // Geçerli ID'leri filtrele
    const validIds = ids.filter((id: string) => mongoose.Types.ObjectId.isValid(id));

    if (validIds.length === 0) {
      return res.status(400).json({
        success: false,
        message: 'Geçerli ID bulunamadı',
      });
    }

    let deletedCount = 0;
    let Model: any;

    // Model seçimi
    switch (resource.toLowerCase()) {
      case 'equipment':
        Model = Equipment;
        break;
      case 'project':
        Model = Project;
        break;
      case 'task':
        Model = Task;
        break;
      case 'user':
        Model = User;
        break;
      case 'maintenance':
        Model = Maintenance;
        break;
      default:
        return res.status(400).json({
          success: false,
          message: 'Geçersiz kaynak tipi',
        });
    }

    // Toplu silme
    const result = await Model.deleteMany({ _id: { $in: validIds } });
    deletedCount = result.deletedCount || 0;

    // Audit log
    for (const id of validIds) {
      await logAction(req, 'DELETE', resource as any, id);
    }

    res.status(200).json({
      success: true,
      deletedCount,
      message: `${deletedCount} öğe başarıyla silindi`,
    });
  } catch (error) {
    logger.error('Toplu silme hatası:', error);
    res.status(500).json({
      success: false,
      message: 'Toplu silme işlemi sırasında bir hata oluştu',
    });
  }
};

// Toplu durum değiştirme
export const bulkUpdateStatus = async (req: Request, res: Response) => {
  try {
    const { resource, ids, status } = req.body;

    if (!resource || !Array.isArray(ids) || ids.length === 0 || !status) {
      return res.status(400).json({
        success: false,
        message: 'Kaynak tipi, ID listesi ve yeni durum gereklidir',
      });
    }

    // Geçerli ID'leri filtrele
    const validIds = ids.filter((id: string) => mongoose.Types.ObjectId.isValid(id));

    if (validIds.length === 0) {
      return res.status(400).json({
        success: false,
        message: 'Geçerli ID bulunamadı',
      });
    }

    let Model: any;
    let statusField = 'status';

    // Model seçimi
    switch (resource.toLowerCase()) {
      case 'equipment':
        Model = Equipment;
        break;
      case 'project':
        Model = Project;
        break;
      case 'task':
        Model = Task;
        break;
      case 'user':
        Model = User;
        statusField = 'isActive';
        break;
      case 'maintenance':
        Model = Maintenance;
        break;
      default:
        return res.status(400).json({
          success: false,
          message: 'Geçersiz kaynak tipi',
        });
    }

    // User için özel durum (isActive boolean)
    const updateData: any = {};
    if (resource.toLowerCase() === 'user') {
      updateData.isActive = status === 'active' || status === true;
    } else {
      updateData[statusField] = status;
    }

    // Toplu güncelleme
    const result = await Model.updateMany(
      { _id: { $in: validIds } },
      { $set: updateData }
    );

    const updatedCount = result.modifiedCount || 0;

    // Audit log
    for (const id of validIds) {
      await logAction(req, 'UPDATE', resource as any, id, [
        {
          field: statusField,
          oldValue: 'unknown',
          newValue: status,
        },
      ]);
    }

    res.status(200).json({
      success: true,
      updatedCount,
      message: `${updatedCount} öğenin durumu güncellendi`,
    });
  } catch (error) {
    logger.error('Toplu durum güncelleme hatası:', error);
    res.status(500).json({
      success: false,
      message: 'Toplu durum güncelleme işlemi sırasında bir hata oluştu',
    });
  }
};

// Toplu atama (görevler için)
export const bulkAssign = async (req: Request, res: Response) => {
  try {
    const { resource, ids, assignedTo } = req.body;

    if (!resource || !Array.isArray(ids) || ids.length === 0 || !assignedTo) {
      return res.status(400).json({
        success: false,
        message: 'Kaynak tipi, ID listesi ve atanan kişi gereklidir',
      });
    }

    // Sadece task'lar için toplu atama
    if (resource.toLowerCase() !== 'task') {
      return res.status(400).json({
        success: false,
        message: 'Toplu atama sadece görevler için kullanılabilir',
      });
    }

    // Geçerli ID'leri filtrele
    const validIds = ids.filter((id: string) => mongoose.Types.ObjectId.isValid(id));

    if (validIds.length === 0) {
      return res.status(400).json({
        success: false,
        message: 'Geçerli ID bulunamadı',
      });
    }

    if (!mongoose.Types.ObjectId.isValid(assignedTo)) {
      return res.status(400).json({
        success: false,
        message: 'Geçersiz kullanıcı ID',
      });
    }

    // Toplu atama
    const result = await Task.updateMany(
      { _id: { $in: validIds } },
      { $set: { assignedTo } }
    );

    const updatedCount = result.modifiedCount || 0;

    // Audit log
    for (const id of validIds) {
      await logAction(req, 'UPDATE', 'Task', id, [
        {
          field: 'assignedTo',
          oldValue: 'unknown',
          newValue: assignedTo,
        },
      ]);
    }

    res.status(200).json({
      success: true,
      updatedCount,
      message: `${updatedCount} görev atandı`,
    });
  } catch (error) {
