// Yeni bakım oluştur
export const createMaintenance = async (req: Request, res: Response) => {
  const session = await mongoose.startSession();
  session.startTransaction();
  try {
    const { equipment, type, description, scheduledDate, status, assignedTo, cost, notes } = req.body;
    const userId = (req as any).user?._id;

    if (!equipment || !type || !description || !scheduledDate || !assignedTo) {
      return res.status(400).json({
        success: false,
        message: 'Ekipman, tip, açıklama, planlanan tarih ve atanan kişi gereklidir',
      });
    }

    if (!mongoose.Types.ObjectId.isValid(equipment)) {
      return res.status(400).json({
        success: false,
        message: 'Geçersiz ekipman ID',
      });
    }

    if (!mongoose.Types.ObjectId.isValid(assignedTo)) {
      return res.status(400).json({
        success: false,
        message: 'Geçersiz kullanıcı ID',
      });
    }

    // Validate and sanitize cost
    const parsedCost = cost !== undefined && cost !== '' ? Number(cost) : undefined;
    if (parsedCost !== undefined && isNaN(parsedCost)) {
      return res.status(400).json({
        success: false,
        message: 'Maliyet geçerli bir sayı olmalıdır'
      });
    }

    // Validate date
    const parsedDate = new Date(scheduledDate);
    if (isNaN(parsedDate.getTime())) {
      return res.status(400).json({
        success: false,
        message: 'Geçersiz tarih formatı'
      });
    }

    const maintenance = await maintenanceService.createMaintenance({
      equipment,
      type,
      description,
      scheduledDate: parsedDate,
      status,
      assignedTo,
      cost: parsedCost,
      notes,
      userId
    }, session);

    const populatedMaintenance = await Maintenance.findById(maintenance._id)
      .populate('equipment', 'name type model')
      .populate('assignedTo', 'name email')
      .session(session);

    await session.commitTransaction();

    res.status(201).json({
      success: true,
      maintenance: populatedMaintenance,
    });
  } catch (error) {
    await session.abortTransaction();
    logger.error('Bakım oluşturma hatası:', error);
    res.status(500).json({
      success: false,
      message: 'Bakım oluşturulurken bir hata oluştu',
    });
  } finally {
    session.endSession();
  }
};

// Bakım güncelle
export const updateMaintenance = async (req: Request, res: Response) => {
  const session = await mongoose.startSession();
  session.startTransaction();
  try {
    const { id } = req.params;
    const { equipment, type, description, scheduledDate, completedDate, status, assignedTo, cost, notes } = req.body;
    const userId = (req as any).user?._id;

    if (!mongoose.Types.ObjectId.isValid(id)) {
      return res.status(400).json({
        success: false,
        message: 'Geçersiz bakım ID',
      });
    }

    // Call Service
    const updatedMaintenance = await maintenanceService.updateMaintenance(id, {
      equipment, type, description, scheduledDate, completedDate, status, assignedTo, cost, notes, userId
    }, session);

    if (!updatedMaintenance) {
      await session.abortTransaction();
      return res.status(404).json({ success: false, message: 'Bakım bulunamadı' });
    }

    const populatedMaintenance = await Maintenance.findById(updatedMaintenance._id)
      .populate('equipment', 'name type model')
      .populate('assignedTo', 'name email')
      .session(session);

    await session.commitTransaction();

    res.status(200).json({
      success: true,
      maintenance: populatedMaintenance,
    });
  } catch (error: any) {
    await session.abortTransaction();
    // Assuming AppError is defined elsewhere or handling as a generic error
    // const appError = error instanceof AppError ? error : new AppError('Sunucu hatası');
    logger.error('Bakım güncelleme hatası:', error);
    res.status(500).json({ // Using 500 directly as AppError is not defined in this context
      success: false,
      message: 'Bakım güncellenirken bir hata oluştu', // Using generic message
    });
  } finally {
    session.endSession();
  }
};

// Bakım sil
export const deleteMaintenance = async (req: Request, res: Response) => {
  try {
    const { id } = req.params;

    if (!mongoose.Types.ObjectId.isValid(id)) {
      return res.status(400).json({
        success: false,
        message: 'Geçersiz bakım ID',
      });
    }

    const maintenance = await Maintenance.findById(id);

    if (!maintenance) {
      return res.status(404).json({
        success: false,
        message: 'Bakım bulunamadı',
      });
    }

    if (maintenance.status === 'IN_PROGRESS') {
      return res.status(400).json({
        success: false,
        message: 'Devam eden bakım silinemez',
      });
    }

    await maintenance.deleteOne();

    res.status(200).json({
      success: true,
      message: 'Bakım başarıyla silindi',
    });
  } catch (error) {
    logger.error('Bakım silme hatası:', error);
    res.status(500).json({
      success: false,
      message: 'Bakım silinirken bir hata oluştu',
    });
  }
};

import { Request, Response } from 'express';
import Media from '../models/Media';
import { uploadToCloudinary, cloudinary } from '../services/cloudinaryService';
import logger from '../utils/logger';

export const getMedia = async (req: Request, res: Response) => {
    try {
        const page = parseInt(req.query.page as string) || 1;
        const limit = parseInt(req.query.limit as string) || 20;
        const type = req.query.type as string;

        const query: any = {};
        if (type) query.type = type;

        const total = await Media.countDocuments(query);
        const media = await Media.find(query)
            .sort({ createdAt: -1 })
            .skip((page - 1) * limit)
            .limit(limit);

        res.json({
            success: true,
            data: media,
            pagination: {
                current: page,
                pages: Math.ceil(total / limit),
                total
            }
        });
    } catch (error) {
        logger.error('Get Media Error:', error);
        res.status(500).json({ success: false, message: 'Medya listelenirken hata oluştu' });
    }
};

export const uploadMedia = async (req: Request, res: Response) => {
    try {
        if (!req.file) {
            return res.status(400).json({ success: false, message: 'Dosya yüklenmedi' });
        }

        const file = req.file;
        // Determine resource type based on mimetype
        const resourceType = file.mimetype.startsWith('video') ? 'video' : 'image';

        // Upload to Cloudinary
        const result = await uploadToCloudinary(file.buffer, file.originalname, {
            folder: 'skproduction/library',
            resource_type: resourceType
        });

        // Save to DB
        const media = await Media.create({
            url: result.secure_url,
            type: resourceType,
            name: file.originalname,
            publicId: result.public_id,
            createdAt: new Date()
        });

        res.status(201).json({
            success: true,
            message: 'Dosya başarıyla yüklendi',
            data: media
        });

    } catch (error) {
        logger.error('Upload Media Error:', error);
        res.status(500).json({ success: false, message: 'Dosya yüklenirken hata oluştu' });
    }
};
export const deleteMedia = async (req: Request, res: Response) => {
    try {
        const { id } = req.params;

        const media = await Media.findById(id);
        if (!media) {
            return res.status(404).json({ success: false, message: 'Medya bulunamadı' });
        }

        // Delete from Cloudinary
        if (media.publicId) {
            await cloudinary.uploader.destroy(media.publicId, { resource_type: media.type });
        }

        // Delete from DB
        await Media.findByIdAndDelete(id);

        res.status(200).json({ success: true, message: 'Medya başarıyla silindi' });
    } catch (error) {
        logger.error('Delete Media Error:', error);
        res.status(500).json({ success: false, message: 'Medya silinirken hata oluştu' });
    }
};

import type { Request, Response } from 'express';
import mongoose from 'mongoose';
import { Session } from '../models';
import logger from '../utils/logger';
import {
  avg,
  getApiMetricsInRange,
  getDbMetricsInRange,
  p95,
  TimeRange,
} from '../utils/monitoring/monitoringStore';
import { rateLimitConfig } from '../middleware/rateLimiters';

const parseTimeRange = (raw: unknown): TimeRange => {
  const v = typeof raw === 'string' ? raw : '';
  if (v === '1h' || v === '24h' || v === '7d' || v === '30d') return v;
  return '24h';
};

export const getMonitoringDashboard = async (req: Request, res: Response) => {
  const timeRange = parseTimeRange(req.query.timeRange);

  try {
    const api = getApiMetricsInRange(timeRange);
    const db = getDbMetricsInRange(timeRange);

    const totalRequests = api.length;
    const errorRequests = api.filter((m) => m.statusCode >= 400).length;
    const successRequests = totalRequests - errorRequests;

    const apiDurations = api.map((m) => m.durationMs);
    const avgApi = avg(apiDurations);
    const p95Api = p95(apiDurations);

    // Slowest endpoints
    const byEndpoint = new Map<string, { endpoint: string; total: number; count: number }>();
    for (const m of api) {
      const key = `${m.method} ${m.path}`;
      const existing = byEndpoint.get(key) || { endpoint: key, total: 0, count: 0 };
      existing.total += m.durationMs;
      existing.count += 1;
      byEndpoint.set(key, existing);
    }
    const slowestEndpoints = Array.from(byEndpoint.values())
      .map((x) => ({
        endpoint: x.endpoint,
        averageTime: x.count ? x.total / x.count : 0,
        requestCount: x.count,
      }))
      .sort((a, b) => b.averageTime - a.averageTime)
      .slice(0, 8);

    // DB slow queries (top)
    const dbByOp = new Map<string, { key: string; total: number; count: number; max: number }>();
    for (const q of db) {
      const key = `${q.model}.${q.operation}`;
      const existing = dbByOp.get(key) || { key, total: 0, count: 0, max: 0 };
      existing.total += q.durationMs;
      existing.count += 1;
      existing.max = Math.max(existing.max, q.durationMs);
      dbByOp.set(key, existing);
    }
    const slowestQueries = Array.from(dbByOp.values())
      .map((x) => ({
        query: x.key,
        averageTime: x.count ? x.total / x.count : 0,
        maxTime: x.max,
        count: x.count,
      }))
      .sort((a, b) => b.averageTime - a.averageTime)
      .slice(0, 8);

    // User activity: Session collection (DB varsa)
    let activeUsers = 0;
    let totalSessions = 0;
    let averageSessionDuration = 0;
    try {
      if (mongoose.connection.readyState === 1) {
        const now = new Date();
        const windowMs =
          timeRange === '1h'
            ? 60 * 60 * 1000
            : timeRange === '24h'
              ? 24 * 60 * 60 * 1000
              : timeRange === '7d'
                ? 7 * 24 * 60 * 60 * 1000
                : 30 * 24 * 60 * 60 * 1000;
        const cutoff = new Date(now.getTime() - windowMs);

        const sessions = await Session.find({
          isActive: true,
          lastActivity: { $gte: cutoff },
        })
          .select('userId createdAt lastActivity')
          .lean();

        totalSessions = sessions.length;
        activeUsers = new Set(sessions.map((s) => s.userId.toString())).size;
        const durations = sessions.map((s: any) => {
          const start = new Date(s.createdAt).getTime();
          const end = new Date(s.lastActivity).getTime();
          return Math.max(0, (end - start) / 1000);
        });
        averageSessionDuration = avg(durations);
      }
    } catch (e) {
      logger.warn('Monitoring: session metrics hesaplanamadı', e);
    }

    // Errors (API tabanlı)
    const byErrorKey = new Map<string, { message: string; count: number; last: number }>();
    for (const m of api) {
      if (m.statusCode < 400) continue;
      const key = `${m.method} ${m.path} -> ${m.statusCode}`;
      const existing = byErrorKey.get(key) || { message: key, count: 0, last: 0 };
      existing.count += 1;
      existing.last = Math.max(existing.last, m.ts);
      byErrorKey.set(key, existing);
    }
    const topErrors = Array.from(byErrorKey.values())
      .sort((a, b) => b.count - a.count)
      .slice(0, 10)
      .map((x) => ({
        message: x.message,
        count: x.count,
        lastOccurred: new Date(x.last || Date.now()).toISOString(),
      }));

    const rateLimited = api.filter((m) => m.statusCode === 429);
    const rateLimitedByEndpoint = new Map<string, number>();
    for (const m of rateLimited) {
      const key = `${m.method} ${m.path}`;
      rateLimitedByEndpoint.set(key, (rateLimitedByEndpoint.get(key) || 0) + 1);
    }
    const topRateLimited = Array.from(rateLimitedByEndpoint.entries())
      .map(([endpoint, count]) => ({ endpoint, count }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 8);

    // Performance: Şimdilik API sürelerinden türet (frontend ölçümü yoksa da gerçek bir sinyal)
    const pageLoadEstimateAvg = avgApi ? Math.min(5000, avgApi * 3) : 0;
    const pageLoadEstimateP95 = p95Api ? Math.min(8000, p95Api * 3) : 0;

    return res.status(200).json({
      performance: {
        averagePageLoadTime: pageLoadEstimateAvg,
        averageApiResponseTime: avgApi,
        p95PageLoadTime: pageLoadEstimateP95,
        p95ApiResponseTime: p95Api,
      },
      apiMetrics: {
        totalRequests,
        successRate: totalRequests ? (successRequests / totalRequests) * 100 : 100,
        errorRate: totalRequests ? (errorRequests / totalRequests) * 100 : 0,
        averageResponseTime: avgApi,
        slowestEndpoints,
      },
      userActivity: {
        activeUsers,
        totalSessions,
        averageSessionDuration,
        topPages: [],
      },
      errors: {
        totalErrors: errorRequests,
        errorRate: totalRequests ? (errorRequests / totalRequests) * 100 : 0,
        topErrors,
      },
      rateLimiting: {
        config: rateLimitConfig(),
        totalRateLimited: rateLimited.length,
        topRateLimitedEndpoints: topRateLimited,
      },
      database: {
        status: mongoose.connection.readyState === 1 ? 'connected' : 'disconnected',
        slowestQueries,
      },
    });
  } catch (error) {
    logger.error('Monitoring dashboard hatası:', error);
    return res.status(500).json({ message: 'Monitoring dashboard verileri alınamadı' });
  }
};

import { Request, Response } from 'express';
import { Notification } from '../models';
import mongoose from 'mongoose';
import logger from '../utils/logger';

// Kullanıcının tüm bildirimlerini getir
export const getUserNotifications = async (req: Request, res: Response) => {
  try {
    const userId = (req.user as any)?.id;

    if (!userId) {
      return res.status(401).json({
        success: false,
        message: 'Kullanıcı kimlik doğrulaması gerekli',
      });
    }

    const { read, type, page = 1, limit = 20 } = req.query;

    const filters: any = { userId };

    if (read !== undefined) {
      filters.read = read === 'true';
    }

    if (type) {
      filters.type = type;
    }

    const pageNumber = parseInt(page as string, 10);
    const limitNumber = parseInt(limit as string, 10);
    const skip = (pageNumber - 1) * limitNumber;

    const [notifications, total, unreadCount] = await Promise.all([
      Notification.find(filters)
        .sort({ createdAt: -1 })
        .skip(skip)
        .limit(limitNumber),
      Notification.countDocuments(filters),
      Notification.countDocuments({ userId, read: false })
    ]);

    res.status(200).json({
      success: true,
      count: notifications.length,
      total,
      unreadCount,
      page: pageNumber,
      totalPages: Math.ceil(total / limitNumber),
      notifications,
    });
  } catch (error) {
    logger.error('Bildirimleri getirme hatası:', error);
    res.status(500).json({
      success: false,
      message: 'Bildirimler getirilirken bir hata oluştu',
    });
  }
};

// Bildirimi okundu olarak işaretle
export const markNotificationAsRead = async (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const userId = (req.user as any)?.id;

    if (!userId) {
      return res.status(401).json({
        success: false,
        message: 'Kullanıcı kimlik doğrulaması gerekli',
      });
    }

    if (!mongoose.Types.ObjectId.isValid(id)) {
      return res.status(400).json({
        success: false,
        message: 'Geçersiz bildirim ID',
      });
    }

    const notification = await Notification.findOneAndUpdate(
      { _id: id, userId },
      { read: true, readAt: new Date() },
      { new: true }
    );

    if (!notification) {
      return res.status(404).json({
        success: false,
        message: 'Bildirim bulunamadı',
      });
    }

    res.status(200).json({
      success: true,
      notification,
    });
  } catch (error) {
    logger.error('Bildirim okundu işaretleme hatası:', error);
    res.status(500).json({
      success: false,
      message: 'Bildirim güncellenirken bir hata oluştu',
    });
