import { Request, Response, NextFunction } from 'express';

const parseAcceptVersion = (acceptHeader: string | undefined) => {
  if (!acceptHeader) return null;
  // ör: application/vnd.skpro.v1+json
  const m = acceptHeader.match(/application\/vnd\.skpro\.v(\d+)\+json/i);
  return m ? m[1] : null;
};

export const apiVersioning = (req: Request, res: Response, next: NextFunction) => {
  const headerVersionRaw = req.header('x-api-version');
  const acceptVersion = parseAcceptVersion(req.header('accept'));
  const version = (headerVersionRaw || acceptVersion || '1').trim();

  // Şimdilik sadece v1 destekliyoruz
  if (version !== '1') {
    return res.status(400).json({
      success: false,
      message: `Desteklenmeyen API versiyonu: v${version}`,
      supported: ['1'],
    });
  }

  res.setHeader('X-API-Version', version);

  // Deprecation warnings (opsiyonel)
  if (process.env.API_V1_DEPRECATED === 'true') {
    res.setHeader('Deprecation', 'true');
    if (process.env.API_V1_SUNSET) {
      res.setHeader('Sunset', process.env.API_V1_SUNSET);
    }
  }

  (req as any).apiVersion = version;
  next();
};

import { Request, Response, NextFunction } from 'express';
import { logAction } from '../utils/auditLogger';
import logger from '../utils/logger';

/**
 * Middleware to automatically log actions
 * Usage: Add to routes that need audit logging
 */
export const auditMiddleware = (
  action: 'CREATE' | 'UPDATE' | 'DELETE' | 'VIEW' | 'EXPORT',
  resource: 'Equipment' | 'Project' | 'Task' | 'User' | 'Client' | 'Maintenance' | 'SiteImage' | 'SiteContent' | 'QRCode' | 'Notification' | 'System'
) => {
  return async (req: Request, res: Response, next: NextFunction) => {
    // Store original json method
    const originalJson = res.json.bind(res);

    // Override json method to capture response
    res.json = function (body: any) {
      // Extract resource ID from response or params
      let resourceId = req.params.id || req.params.equipmentId || req.params.projectId || 
                       req.params.taskId || req.params.userId || req.params.clientId || 
                       req.params.maintenanceId || body?._id || body?.id || 'unknown';

      // Convert to string if it's an object
      if (typeof resourceId === 'object' && resourceId !== null) {
        resourceId = resourceId.toString();
      }

      // Log the action asynchronously (don't wait)
      logAction(req, action, resource, resourceId as string).catch(err => {
        // Silently fail - audit logging should not break the main flow
        logger.error('Audit log error:', err);
      });

      // Call original json method
      return originalJson(body);
    };

    next();
  };
};

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { User } from '../models';
import { Permission, hasPermission, hasRole, Role } from '../config/permissions';
import logger from '../utils/logger';
import { JWT_SECRET } from '../utils/authTokens';
import { IUser } from '../models/User';
import { updateSessionActivity } from '../controllers/session.controller';

declare global {
  namespace Express {
    interface Request {
      user?: IUser;
    }
  }
}

// JWT doğrulama middleware'i
export const authenticate = async (
  req: Request,
  res: Response,
  next: NextFunction
) => {
  try {
    // Token'ı header'dan veya cookie'den al
    let token;
    if (
      req.headers.authorization &&
      req.headers.authorization.startsWith('Bearer')
    ) {
      token = req.headers.authorization.split(' ')[1];
    } else if (req.cookies?.accessToken) {
      token = req.cookies.accessToken;
    }

    // Token yoksa yetkisiz
    if (!token) {
      return res.status(401).json({
        success: false,
        message: 'Bu işlem için giriş yapmanız gerekiyor',
      });
    }

    // JWT verify et
    const decoded = jwt.verify(token, JWT_SECRET) as jwt.JwtPayload;

    // Kullanıcıyı database'den çek
    const user = await User.findById(decoded.id).select('-password');

    if (!user || !user.isActive) {
      return res.status(401).json({
        success: false,
        message: 'Geçersiz token veya yetkisiz kullanıcı',
      });
    }

    // Session check BYPASSED (acil kurtarma için kaldırıldı)
    logger.info('Auth Check Bypassed - Session DB Check Removed', {
      userId: user._id,
    });

    // Session activity güncelle (background, hata patlatmaz)
    updateSessionActivity(user._id.toString(), token).catch((err: any) =>
      logger.error('Session activity güncelleme hatası:', err)
    );

    // Request'e kullanıcı bilgisini ekle
    req.user = user as IUser;
    next();
  } catch (error: any) {
    const errorMessage =
      error.name === 'JsonWebTokenError'
        ? 'Geçersiz token. Lütfen tekrar giriş yapın.'
        : error.name === 'TokenExpiredError'
          ? 'Token süresi dolmuş. Lütfen tekrar giriş yapın.'
          : 'Yetkilendirme başarısız';

    logger.error('Kimlik doğrulama hatası:', {
      name: error.name,
      message: error.message,
      path: req.path,
    });

    res.status(401).json({
      success: false,
      message: errorMessage,
      name: error.name,
    });
  }
};

// Rol bazlı yetkilendirme middleware'i
export const authorize = (...roles: string[]) => {
  return (req: Request, res: Response, next: NextFunction) => {
    if (!req.user) {
      return res.status(401).json({
        success: false,
        message: 'Yetkilendirme başarısız',
      });
    }

    // Admin ve Firma Sahibi her şeye erişebilir
    if (hasRole(req.user.role, Role.ADMIN, Role.FIRMA_SAHIBI)) {
      return next();
    }

    if (!roles.includes(req.user.role)) {
      return res.status(403).json({
        success: false,
        message: 'Bu işlem için yetkiniz bulunmuyor',
      });
    }

    next();
  };
};

// Yetki bazlı yetkilendirme middleware'i
export const requirePermission = (permission: Permission) => {
  return (req: Request, res: Response, next: NextFunction) => {
    if (!req.user) {
      return res.status(401).json({
        success: false,
        message: 'Yetkilendirme başarısız',
      });
    }

    // Admin ve Firma Sahibi her şeye erişebilir
    if (hasRole(req.user.role, Role.ADMIN, Role.FIRMA_SAHIBI)) {
      return next();
    }

    // Kullanıcının özel yetkilerini kontrol et
    const userPermissions = req.user.permissions || [];
    if (!hasPermission(req.user.role, permission, userPermissions)) {
      return res.status(403).json({
        success: false,
        message: 'Bu işlem için yetkiniz bulunmuyor',
      });
    }

    next();
  };
};

import { Request, Response, NextFunction } from 'express';
import { getCache, setCache, createCacheKey } from '../utils/cache';
import logger from '../utils/logger';

export interface CacheMiddlewareOptions {
  ttl?: number; // Time to live in seconds (default: 300 = 5 minutes)
  keyPrefix?: string; // Cache key prefix
  skipCache?: (req: Request) => boolean; // Cache'i atlamak için koşul
  generateKey?: (req: Request & { user?: any }) => string; // Özel cache key oluşturma fonksiyonu
}

/**
 * API response caching middleware
 * GET istekleri için cache kontrolü yapar
 */
export const cacheMiddleware = (options: CacheMiddlewareOptions = {}) => {
  const {
    ttl = 300, // Default 5 dakika
    keyPrefix = 'api',
    skipCache,
    generateKey,
  } = options;

  return async (req: Request & { user?: any }, res: Response, next: NextFunction) => {
    // Sadece GET isteklerini cache'le
    if (req.method !== 'GET') {
      return next();
    }

    // Skip cache koşulu varsa kontrol et
    if (skipCache && skipCache(req)) {
      return next();
    }

    try {
      // Cache key oluştur
      const cacheKey = generateKey
        ? generateKey(req)
        : createCacheKey(
            keyPrefix,
            req.path,
            JSON.stringify(req.query),
            req.headers.authorization ? 'auth' : 'public'
          );

      // Cache'den veri getir
      const cached = await getCache<any>(cacheKey);
      if (cached) {
        logger.debug(`Cache hit: ${cacheKey}`);
        return res.status(200).json(cached);
      }

      // Cache'de yoksa, response'u yakala ve cache'le
      const originalJson = res.json.bind(res);
      res.json = function (body: any) {
        // Başarılı response'ları cache'le
        if (res.statusCode === 200 && body) {
          setCache(cacheKey, body, ttl).catch((error) => {
            logger.error(`Cache set error for ${cacheKey}:`, error);
          });
        }
        return originalJson(body);
      };

      next();
    } catch (error) {
      logger.error('Cache middleware error:', error);
      // Hata durumunda cache'i atla
      next();
    }
  };
};

/**
 * Belirli bir resource için cache'i invalidate et
 */
export const invalidateCache = async (
  pattern: string | string[]
): Promise<void> => {
  const { deleteCachePattern } = await import('../utils/cache');

  if (Array.isArray(pattern)) {
    await Promise.all(pattern.map((p) => deleteCachePattern(p)));
  } else {
    await deleteCachePattern(pattern);
  }
};

