import { Request, Response, NextFunction } from 'express';
import { ZodError } from 'zod';
import logger from '../utils/logger';
import * as Sentry from '@sentry/node';

export class AppError extends Error {
  statusCode: number;
  status: string;
  isOperational: boolean;

  constructor(message: string, statusCode: number) {
    super(message);
    this.statusCode = statusCode;
    this.status = `${statusCode}`.startsWith('4') ? 'fail' : 'error';
    this.isOperational = true;

    Error.captureStackTrace(this, this.constructor);
  }
}

export const errorHandler = (
  err: Error | AppError | ZodError,
  req: Request,
  res: Response,
  _next: NextFunction
) => {
  if (err instanceof AppError) {
    return res.status(err.statusCode).json({
      success: false,
      status: err.status,
      message: err.message,
    });
  }

  if (err instanceof ZodError) {
    return res.status(400).json({
      success: false,
      status: 'fail',
      message: 'Validation error',
      errors: err.errors,
    });
  }

  // MongoDB duplicate key error
  if (err.name === 'MongoError' && (err as any).code === 11000) {
    return res.status(409).json({
      success: false,
      status: 'fail',
      message: 'Duplicate field value entered',
    });
  }

  // MongoDB validation error
  if (err.name === 'ValidationError') {
    return res.status(400).json({
      success: false,
      status: 'fail',
      message: 'Validation error',
      errors: Object.values((err as any).errors).map((el: any) => el.message),
    });
  }

  // JWT errors
  if (err.name === 'JsonWebTokenError') {
    return res.status(401).json({
      success: false,
      status: 'fail',
      message: 'Invalid token. Please log in again!',
    });
  }

  if (err.name === 'TokenExpiredError') {
    return res.status(401).json({
      success: false,
      status: 'fail',
      message: 'Your token has expired! Please log in again.',
    });
  }

  // Sentry Capture for 500 errors
  if (!('statusCode' in err) || (err as any).statusCode === 500) {
    Sentry.captureException(err);
  }

  // Default error
  logger.error('Unhandled error:', {
    error: err,
    message: err.message,
    stack: err.stack,
    name: err.name,
    path: req.path,
    method: req.method,
  });

  // Response henüz gönderilmediyse gönder
  if (!res.headersSent) {
    const isTestOrDev = process.env.NODE_ENV === 'development' || process.env.NODE_ENV === 'test';
    return res.status(500).json({
      success: false,
      status: 'error',
      message: isTestOrDev
        ? (err.message || 'Internal Server Error')
        : 'Internal Server Error',
      ...(isTestOrDev ? {
        details: err.stack,
        name: err.name,
        path: req.path,
        method: req.method
      } : {}),
    });
  } else {
    logger.warn('Error handler called but response already sent', { path: req.path });
  }
};

import type { NextFunction, Request, Response } from 'express';

type AnyObject = Record<string, any>;

const isPlainObject = (v: any): v is AnyObject => {
  if (!v || typeof v !== 'object') return false;
  const proto = Object.getPrototypeOf(v);
  return proto === Object.prototype || proto === null;
};

const sanitize = (input: any): any => {
  if (Array.isArray(input)) {
    return input.map(sanitize);
  }
  if (isPlainObject(input)) {
    const out: AnyObject = {};
    for (const [key, value] of Object.entries(input)) {
      // NoSQL injection: $operators ve dotted path'leri engelle
      if (key.startsWith('$') || key.includes('.')) continue;
      out[key] = sanitize(value);
    }
    return out;
  }
  return input;
};

export const mongoSanitize = (req: Request, _res: Response, next: NextFunction) => {
  if (req.body) req.body = sanitize(req.body);
  if (req.query) req.query = sanitize(req.query);
  if (req.params) req.params = sanitize(req.params);
  return next();
};

import rateLimit from 'express-rate-limit';
import jwt from 'jsonwebtoken';
import type { Request } from 'express';

const parseNumber = (raw: any, fallback: number) => {
  const n = Number(raw);
  return Number.isFinite(n) && n > 0 ? n : fallback;
};

const getTokenFromReq = (req: Request): string | null => {
  const h = req.headers.authorization;
  if (typeof h === 'string' && h.startsWith('Bearer ')) return h.slice('Bearer '.length);
  return null;
};

const keyByUserOrIp = (req: Request): string => {
  try {
    const token = getTokenFromReq(req);
    if (token) {
      // Merkezi JWT_SECRET kullan
      const { JWT_SECRET } = require('../utils/authTokens');
      const decoded = jwt.verify(token, JWT_SECRET) as any;
      const userId = decoded?.id || decoded?._id || decoded?.userId;
      if (userId) return `user:${String(userId)}`;
    }
  } catch {
    // ignore
  }
  // fallback ip
  return `ip:${req.ip}`;
};

export const createRateLimiter = (opts: {
  windowMs: number;
  max: number;
  keyStrategy?: 'ip' | 'user_or_ip';
  customMessage?: string;
}) => {
  const minutes = Math.ceil(opts.windowMs / (60 * 1000));
  const defaultMessage = opts.customMessage || `Çok fazla istek. Lütfen ${minutes} dakika sonra tekrar deneyin.`;

  // Test ve development ortamında rate limiting'i tamamen devre dışı bırak
  // TestSprite gibi otomasyon testleri için gerekli
  const isTestEnv = process.env.NODE_ENV === 'test' || 
                    process.env.NODE_ENV === 'development' || 
                    process.env.DISABLE_RATE_LIMIT === 'true';

  return rateLimit({
    windowMs: opts.windowMs,
    max: opts.max,
    standardHeaders: true,
    legacyHeaders: false,
    skip: (req) => {
      // OPTIONS isteklerini her zaman atla
      if (req.method === 'OPTIONS') return true;
      // Test ortamında tüm istekleri atla
      if (isTestEnv) return true;
      return false;
    },
    keyGenerator: (req) => {
      if (opts.keyStrategy === 'user_or_ip') return keyByUserOrIp(req);
      return `ip:${req.ip}`;
    },
    message: { success: false, message: defaultMessage, code: 'RATE_LIMITED' },
  });
};

// Defaults (env ile override edilebilir)
const WINDOW_15M = 15 * 60 * 1000;

export const generalApiLimiter = createRateLimiter({
