import jwt from 'jsonwebtoken';
import { Session, User } from '../models';
import { IUser } from '../models/User';
import { AppError } from '../types/common';
import { createTokenHash, generateTokenPair, TokenPair, JWT_REFRESH_SECRET } from '../utils/authTokens';
import logger from '../utils/logger';

export interface LoginResult {
    user: IUser;
    tokens?: TokenPair;
    requires2FA?: boolean;
}

export interface RefreshResult {
    accessToken: string;
    refreshToken: string;
}

class AuthService {
    /**
     * Authenticate user with email/phone and password
     */
    async login(identifier: string, password: string, ip: string, userAgent: string): Promise<LoginResult> {
        const identifierRaw = identifier.trim();
        const isEmail = identifierRaw.includes('@');
        const identifierEmail = isEmail ? identifierRaw.toLowerCase() : '';
        const identifierPhone = !isEmail ? identifierRaw.replace(/[^\d+]/g, '') : '';

        // Find user
        const user = await User.findOne({
            $or: [
                ...(identifierEmail ? [{ email: identifierEmail }] : []),
                ...(identifierPhone ? [{ phone: identifierPhone }, { phone: identifierRaw }] : []),
            ],
        });

        if (!user) {
            throw new AppError('Geçersiz email ya da şifre', 401);
        }

        if (!user.isActive) {
            throw new AppError('Hesabınız devre dışı bırakılmış', 401);
        }

        const isPasswordValid = await user.comparePassword(password);
        if (!isPasswordValid) {
            throw new AppError('Geçersiz email ya da şifre', 401);
        }

        // 2FA Check
        if (user.is2FAEnabled) {
            return { user, requires2FA: true };
        }

        // Generate Tokens
        const tokens = generateTokenPair(user);

        // Create Session
        try {
            await Session.create({
                userId: user._id,
                token: createTokenHash(tokens.accessToken),
                refreshToken: createTokenHash(tokens.refreshToken),
                deviceInfo: {
                    userAgent: userAgent,
                    ipAddress: ip,
                },
                lastActivity: new Date(),
                expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000), // 7 days
                isActive: true,
            });
        } catch (sessionError) {
            // Non-blocking but log it
            logger.warn('Session create failed:', sessionError);
        }

        return { user, tokens };
    }

    /**
     * Refresh access token
     */
    async refreshToken(refreshTokenRaw: string): Promise<RefreshResult> {
        // Verify token
        let decoded: any;
        try {
            decoded = jwt.verify(refreshTokenRaw, JWT_REFRESH_SECRET);
        } catch (error: unknown) {
            // Token expired or invalid signature
            throw new AppError('Geçersiz veya süresi dolmuş token', 401);
        }

        if (!decoded || !decoded.id) {
            throw new AppError('Token payload geçersiz', 401);
        }

        // Check Session
        let session;
        try {
            const refreshHash = createTokenHash(refreshTokenRaw);
            session = await Session.findOne({
                userId: decoded.id,
                refreshToken: refreshHash,
                isActive: true,
                expiresAt: { $gt: new Date() },
            });
        } catch (dbError) {
            logger.error('Session lookup failed during refresh:', dbError);
            throw new AppError('Oturum doğrulanamadı', 401);
        }

        if (!session) {
            // Session expired or logged out
            throw new AppError('Oturum süresi dolmuş veya geçersiz', 401);
        }

        // Check User
        let user;
        try {
            user = await User.findById(decoded.id);
        } catch (dbError) {
            logger.error('User lookup failed during refresh:', dbError);
            throw new AppError('Kullanıcı doğrulanamadı', 401);
        }

        if (!user || !user.isActive) {
            throw new AppError('Kullanıcı bulunamadı veya pasif', 401);
        }

        // Generate new pair
        const tokens = generateTokenPair(user);

        // Rotate Session
        try {
            await Session.updateOne(
                { _id: session._id },
                {
                    token: createTokenHash(tokens.accessToken),
                    refreshToken: createTokenHash(tokens.refreshToken),
                    lastActivity: new Date(),
                    expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
                }
            );
        } catch (error) {
            logger.warn('Session rotation failed:', error);
            // Even if rotation fails, we continue as returning tokens is priority
            // But we should probably not fail the request if we can't rotate, 
            // just log it as we did. 
        }

        return {
            accessToken: tokens.accessToken,
            refreshToken: tokens.refreshToken
        };
    }

    /**
     * Logout
     */
    async logout(refreshTokenRaw?: string): Promise<void> {
        if (refreshTokenRaw) {
            const refreshHash = createTokenHash(refreshTokenRaw);
            await Session.updateMany(
                { refreshToken: refreshHash, isActive: true },
                { isActive: false }
            );
        }
    }

    /**
     * Get Profile
     */
    async getProfile(userId: string): Promise<IUser> {
        const user = await User.findById(userId).select('-password');
        if (!user) {
            throw new AppError('Kullanıcı bulunamadı', 404);
        }
        return user;
    }

    /**
     * Update Profile
     */
    async updateProfile(userId: string, data: { name?: string; email?: string }): Promise<IUser> {
        const updateData: Record<string, unknown> = {};
        if (data.name) updateData.name = data.name;
        if (data.email) updateData.email = data.email;

        const updatedUser = await User.findByIdAndUpdate(
            userId,
            updateData,
            { new: true, runValidators: true }
        ).select('-password');

        if (!updatedUser) {
            throw new AppError('Kullanıcı bulunamadı', 404);
        }
        return updatedUser;
    }

    /**
     * Change Password
     */
    async changePassword(userId: string, current: string, nextPass: string): Promise<void> {
        const user = await User.findById(userId);
        if (!user) {
            throw new AppError('Kullanıcı bulunamadı', 404);
        }

        const isValid = await user.comparePassword(current);
        if (!isValid) {
            throw new AppError('Mevcut şifre yanlış', 401);
        }

        user.password = nextPass;
        await user.save();
    }
}

export default new AuthService();

import User from '../models/User';
import googleCalendarService from './googleCalendar.service';
import outlookCalendarService from './outlookCalendar.service';
import logger from '../utils/logger';

class CalendarSyncService {
    /**
     * Sycns a project event to all assigned team members.
     * This is an asynchronous fire-and-forget method.
     */
    async syncProjectEvent(project: any, isUpdate: boolean = false): Promise<void> {
        try {
            if (!project.team || project.team.length === 0) return;

            const projectTeamIds = project.team.map((user: any) => user._id || user);
            const users = await User.find({ _id: { $in: projectTeamIds } }).select('+googleTokens +outlookTokens').lean();

            const eventData = {
                summary: `Proje: ${project.name}`,
                description: `Açıklama: ${project.description || 'Belirtilmedi'}\nDurum: ${project.status}`,
                location: project.location?.address || 'Belirtilmedi',
                startDate: project.startDate,
                endDate: project.endDate || project.startDate,
                attendees: users.map(u => u.email)
            };

            for (const user of users) {
                // Determine if we need to create/update
                // NOTE: In a complete implementation, you would store the generated Google/Outlook Event ID in a mapping table
                // For this skeleton, we assume creation or skip update if mapping doesn't exist

                if (user.googleTokens?.accessToken && !isUpdate) {
                    await googleCalendarService.createEvent(user.googleTokens.accessToken, eventData);
                    logger.info(`Google Calendar event synced for user ${user.email}`);
                }

