        resourceId: mockResourceId.toString(),
        changes: [{ field: 'name', oldValue: 'Old', newValue: 'New' }],
        metadata: { ipAddress: '127.0.0.1' },
      });

      expect(mockCreate).toHaveBeenCalledWith(
        expect.objectContaining({
          user: mockUserId,
          action: 'CREATE',
          resource: 'Project',
          resourceId: mockResourceId,
          changes: [{ field: 'name', oldValue: 'Old', newValue: 'New' }],
          metadata: { ipAddress: '127.0.0.1' },
        })
      );
    });

