/**
 * Aggregation pipeline'ı optimize eder
 * - Gereksiz stage'leri kaldırır
 * - Index kullanımını optimize eder
 * - Memory kullanımını azaltır
 * 
 * @param pipeline - Optimize edilecek pipeline
 * @param options - Optimizasyon seçenekleri
 * @returns Optimize edilmiş pipeline
 */
export const optimizeAggregation = (
  pipeline: any[],
  _options: {
    allowDiskUse?: boolean;
    explain?: boolean;
    hint?: any;
  } = {}
): any[] => {
  const optimized: any[] = [];
  let hasMatch = false;
  let hasSort = false;
  let hasLimit = false;

  for (let i = 0; i < pipeline.length; i++) {
    const stage = pipeline[i];
    const stageKey = Object.keys(stage)[0];

    // $match stage'ini mümkün olduğunca erken taşı
    if (stageKey === '$match' && !hasMatch) {
      optimized.unshift(stage); // En başa ekle
      hasMatch = true;
      continue;
    }

    // $sort ve $limit'i birleştir (MongoDB optimize eder)
    if (stageKey === '$sort' && !hasSort) {
      hasSort = true;
      optimized.push(stage);

      // Sonraki stage $limit ise birleştir
      if (i + 1 < pipeline.length && pipeline[i + 1].$limit) {
        optimized.push(pipeline[i + 1]);
        hasLimit = true;
        i++; // $limit'i atla
        continue;
      }
      continue;
    }

    // $limit zaten $sort ile birleştirildiyse atla
    if (stageKey === '$limit' && hasLimit) {
      continue;
    }

    // $project stage'inde sadece gerekli alanları tut
    if (stageKey === '$project') {
      const projectStage = optimizeProjectStage(stage.$project);
      if (Object.keys(projectStage).length > 0) {
        optimized.push({ $project: projectStage });
      }
      continue;
    }

    // Diğer stage'leri olduğu gibi ekle
    optimized.push(stage);
  }

  // $match yoksa ve ilk stage'de filtreleme yapılabiliyorsa ekle
  if (!hasMatch && optimized.length > 0) {
    const firstStage = optimized[0];
    const firstKey = Object.keys(firstStage)[0];

    // $group veya $lookup'tan önce $match eklenebilir
    if (firstKey === '$group' || firstKey === '$lookup') {
      // İlk stage'e göre $match eklenebilir (opsiyonel)
    }
  }

  return optimized;
};

/**
 * $project stage'ini optimize eder
 * Sadece gerekli alanları tutar
 */
const optimizeProjectStage = (project: any): any => {
  const optimized: any = {};

  for (const [key, value] of Object.entries(project)) {
    // 0 (exclude) değerleri atla (zaten exclude edilmiş)
    if (value === 0 || value === false) {
      continue;
    }

    // 1 (include) veya expression'ları ekle
    optimized[key] = value;
  }

  return optimized;
};

/**
 * Aggregation pipeline'ı explain eder ve performans analizi yapar
 */
export const explainAggregation = async (
  model: mongoose.Model<any>,
  pipeline: any[],
  _options: {
    allowDiskUse?: boolean;
    hint?: any;
  } = {}
): Promise<any> => {
  try {
    const explainResult = await model.aggregate(pipeline).explain('executionStats');

    if (process.env.NODE_ENV === 'development' && process.env.DEBUG_QUERIES === 'true') {
      logger.debug('Aggregation Explain:', {
        stages: explainResult.stages || [],
        executionStats: explainResult.executionStats,
        queryPlanner: explainResult.queryPlanner,
      });
    }

    return explainResult;
  } catch (error) {
    logger.error('Aggregation explain error:', error);
    return null;
  }
};

/**
 * Aggregation pipeline'ı index kullanımı için optimize eder
 * $match stage'lerinde kullanılan alanlar için index önerileri verir
 */
export const suggestIndexesForAggregation = (pipeline: any[]): string[] => {
  const suggestions: string[] = [];
  const matchFields: Set<string> = new Set();
  const sortFields: Set<string> = new Set();

  for (const stage of pipeline) {
    // $match stage'lerindeki alanları topla
    if (stage.$match) {
      for (const field of Object.keys(stage.$match)) {
        matchFields.add(field);
      }
    }

    // $sort stage'lerindeki alanları topla
    if (stage.$sort) {
      for (const field of Object.keys(stage.$sort)) {
        sortFields.add(field);
      }
    }
  }

  // $match ve $sort alanlarını birleştirerek index öner
  if (matchFields.size > 0 || sortFields.size > 0) {
    const allFields = Array.from(new Set([...matchFields, ...sortFields]));

    // Compound index öner (match alanları + sort alanları)
    if (allFields.length > 0) {
      suggestions.push(`Compound index: ${allFields.join(', ')}`);
    }
  }

  return suggestions;
};

/**
 * Aggregation pipeline'ı memory kullanımı için optimize eder
 * Büyük veri setleri için allowDiskUse ve cursor kullanımını önerir
 */
export const optimizeForMemory = (
  pipeline: any[],
  estimatedDataSize: number = 0
): { pipeline: any[]; options: any } => {
  const options: any = {};

  // Büyük veri setleri için allowDiskUse öner
  if (estimatedDataSize > 100 * 1024 * 1024) { // 100MB
    options.allowDiskUse = true;
  }

  // $group stage'lerinde memory kullanımını azalt
  const optimized = pipeline.map(stage => {
    if (stage.$group) {
      // $group içinde gereksiz alanları kaldır
      const optimizedGroup: any = {};
      for (const [key, value] of Object.entries(stage.$group)) {
        // Sadece gerekli aggregation operatörlerini tut
        if (typeof value === 'object' && value !== null) {
          optimizedGroup[key] = value;
        }
      }
      return { $group: optimizedGroup };
    }
    return stage;
  });

  return { pipeline: optimized, options };
};

/**
 * Aggregation pipeline'ı batch processing için optimize eder
 * Büyük sonuç setleri için cursor kullanımını sağlar
 */
export const optimizeForBatchProcessing = (
  pipeline: any[],
  batchSize: number = 1000
): any[] => {
  // $limit yoksa batch size ekle
  const hasLimit = pipeline.some(stage => stage.$limit);
  if (!hasLimit) {
    pipeline.push({ $limit: batchSize });
  }

  return pipeline;
};

import { Request } from 'express';
import mongoose from 'mongoose';
import AuditLog from '../models/AuditLog';
import logger from './logger';

export interface AuditLogData {
  user: string | null; // User ID (null for system actions)
  action: 'CREATE' | 'UPDATE' | 'DELETE' | 'VIEW' | 'EXPORT' | 'IMPORT' | 'LOGIN' | 'LOGOUT' | 'PERMISSION_CHANGE';
  resource: 'Equipment' | 'Project' | 'Task' | 'User' | 'Client' | 'Maintenance' | 'SiteImage' | 'SiteContent' | 'QRCode' | 'Notification' | 'PushSubscription' | 'NotificationSettings' | 'Widget' | 'System' | 'ReportSchedule' | 'SavedSearch' | 'Session';
  resourceId: string;
  changes?: Array<{
    field: string;
    oldValue: any;
    newValue: any;
  }>;
  metadata?: {
    ipAddress?: string;
    userAgent?: string;
    method?: string;
    endpoint?: string;
    [key: string]: any;
  };
}

/**
 * Create an audit log entry
 */
export const createAuditLog = async (data: AuditLogData): Promise<void> => {
  try {
    // resourceId'yi ObjectId'ye çevir (string ise)
    let resourceIdObjectId: mongoose.Types.ObjectId;
    if (typeof data.resourceId === 'string') {
      if (mongoose.Types.ObjectId.isValid(data.resourceId)) {
        resourceIdObjectId = new mongoose.Types.ObjectId(data.resourceId);
      } else {
        logger.warn('Geçersiz resourceId formatı:', data.resourceId);
        return; // Geçersiz ID ise audit log oluşturma
      }
    } else {
      resourceIdObjectId = data.resourceId as mongoose.Types.ObjectId;
    }

    // user field'ını ObjectId'ye çevir (string ise) veya null bırak
    let userObjectId: mongoose.Types.ObjectId | null = null;
    if (data.user) {
      if (typeof data.user === 'string') {
        // "system" veya geçersiz string'ler için null kullan
        if (data.user.toLowerCase() === 'system' || !mongoose.Types.ObjectId.isValid(data.user)) {
          logger.warn('Geçersiz user ID formatı (system veya invalid):', data.user);
          userObjectId = null; // System action olarak işaretle
        } else {
          userObjectId = new mongoose.Types.ObjectId(data.user);
        }
      } else if (typeof data.user === 'object' && mongoose.Types.ObjectId.isValid(data.user as any)) {
        userObjectId = data.user as unknown as mongoose.Types.ObjectId;
      }
    }

    await AuditLog.create({
      user: userObjectId, // ObjectId veya null
      action: data.action,
      resource: data.resource,
      resourceId: resourceIdObjectId,
      changes: data.changes || [],
      metadata: data.metadata || {},
    });
  } catch (error) {
    // Log error but don't throw - audit logging should not break the main flow
    logger.error('Audit log oluşturma hatası:', error);
  }
};

/**
 * Login işlemi için özel audit log fonksiyonu
 * Login sırasında req.user henüz yok, bu yüzden user ID'yi direkt alır
 */
export const logLoginAction = async (
  userId: string,
  req: Request
): Promise<void> => {
  try {
    if (!userId || !mongoose.Types.ObjectId.isValid(userId)) {
      logger.warn('Geçersiz user ID for login audit log:', userId);
      return;
    }

    await createAuditLog({
      user: userId,
      action: 'LOGIN',
      resource: 'User',
      resourceId: userId,
      metadata: {
        ipAddress: req.ip || req.socket?.remoteAddress || undefined,
        userAgent: req.get?.('user-agent') || undefined,
        method: req.method,
        endpoint: req.originalUrl || req.url,
      },
    });
  } catch (error) {
    // Audit log hatası ana işlemi engellemesin - sadece logla
    logger.error('Login audit log oluşturma hatası:', error);
  }
};

/**
 * Express request'ten audit log oluşturur
 * @param req - Express request objesi
 * @param action - Yapılan işlem (CREATE, UPDATE, DELETE, vb.)
 * @param resource - Kaynak tipi (Equipment, Project, vb.)
 * @param resourceId - Kaynak ID
 * @param changes - Değişiklikler (opsiyonel)
 * @example
 * await logAction(req, 'CREATE', 'Equipment', equipmentId, changes);
 */
export const logAction = async (
  req: Request,
  action: AuditLogData['action'],
  resource: AuditLogData['resource'],
  resourceId: string,
  changes?: AuditLogData['changes']
): Promise<void> => {
  try {
    // User ID'yi al, yoksa null kullan (system actions için)
    const userId = (req.user as any)?.id || (req.user as any)?._id?.toString() || null;

    // userId'nin geçerli bir ObjectId olup olmadığını kontrol et
    let validUserId: string | null = null;
    if (userId && typeof userId === 'string' && /^[0-9a-f]{24}$/i.test(userId)) {
      validUserId = userId;
    }

    await createAuditLog({
      user: validUserId || null, // null olabilir (system actions için)
      action,
      resource,
      resourceId,
      changes,
      metadata: {
        ipAddress: req.ip || req.socket?.remoteAddress || undefined,
        userAgent: req.get('user-agent') || undefined,
        method: req.method,
        endpoint: req.originalUrl || req.url,
      },
    });
  } catch (error) {
    // Audit log hatası ana işlemi engellemesin - sadece logla
    logger.error('Audit log oluşturma hatası:', error);
  }
};

/**
 * İki objeyi karşılaştırır ve değişiklikleri çıkarır
 * @param oldData - Eski veri
 * @param newData - Yeni veri
 * @returns Değişiklikler dizisi
 * @example
 * const changes = extractChanges(oldEquipment, newEquipment);
 * // [{ field: 'name', oldValue: 'Old Name', newValue: 'New Name' }]
 */
export const extractChanges = (oldData: any, newData: any): AuditLogData['changes'] => {
  const changes: AuditLogData['changes'] = [];

  if (!oldData || !newData) {
    return changes;
  }

  const allKeys = new Set([...Object.keys(oldData), ...Object.keys(newData)]);

  allKeys.forEach((key) => {
    // Skip internal fields
    if (['_id', '__v', 'createdAt', 'updatedAt', 'password'].includes(key)) {
      return;
    }

    const oldValue = oldData[key];
    const newValue = newData[key];

    // Deep comparison for objects
    if (JSON.stringify(oldValue) !== JSON.stringify(newValue)) {
      changes.push({
        field: key,
        oldValue: oldValue !== undefined ? oldValue : null,
        newValue: newValue !== undefined ? newValue : null,
      });
    }
  });

  return changes;
};

/**
 * Filtrelenmiş audit log'ları getirir
 * @param filters - Filtre seçenekleri
 * @param filters.user - Kullanıcı ID (opsiyonel)
 * @param filters.resource - Kaynak tipi (opsiyonel)
 * @param filters.resourceId - Kaynak ID (opsiyonel)
 * @param filters.action - İşlem tipi (opsiyonel)
 * @param filters.startDate - Başlangıç tarihi (opsiyonel)
 * @param filters.endDate - Bitiş tarihi (opsiyonel)
 * @param filters.page - Sayfa numarası (default: 1)
 * @param filters.limit - Sayfa başına kayıt (default: 50)
 * @returns Filtrelenmiş audit log'ları ve pagination bilgisi
 * @example
 * const { logs, total, page, totalPages } = await getAuditLogs({ user: '123', page: 1, limit: 20 });
 */
export const getAuditLogs = async (filters: {
  user?: string;
  resource?: string;
  resourceId?: string;
  action?: string;
  startDate?: Date;
  endDate?: Date;
  page?: number;
  limit?: number;
}) => {
  const query: any = {};

  if (filters.user) {
    query.user = filters.user;
  }

  if (filters.resource) {
    query.resource = filters.resource;
  }

  if (filters.resourceId) {
    query.resourceId = filters.resourceId;
  }

  if (filters.action) {
    query.action = filters.action;
  }

  if (filters.startDate || filters.endDate) {
    query.createdAt = {};
    if (filters.startDate) {
      query.createdAt.$gte = filters.startDate;
    }
    if (filters.endDate) {
      query.createdAt.$lte = filters.endDate;
    }
  }

  const page = filters.page || 1;
  const limit = filters.limit || 50;
  const skip = (page - 1) * limit;

  // Performans optimizasyonu: lean() kullan ve populate'i optimize et
  const [logs, total] = await Promise.all([
    AuditLog.find(query)
      .populate('user', 'name email role')
      .sort({ createdAt: -1 })
      .skip(skip)
      .limit(limit)
      .lean(), // Lean query - daha hızlı
    AuditLog.countDocuments(query),
  ]);

  return {
    logs,
    total,
    page,
    totalPages: Math.ceil(total / limit),
  };
};

import crypto from 'crypto';
import jwt from 'jsonwebtoken';
import type { IUser } from '../models/User';
import logger from './logger';

export type AccessTokenPayload = {
  id: string;
  email: string;
  role: string;
};

export type TokenPair = {
  accessToken: string;
  refreshToken: string;
};

// JWT_SECRET'ları merkezi bir yerden al - tutarlılık için
// TÜM yerlerde aynı secret kullanılması için export ediyoruz
export const JWT_SECRET = process.env.JWT_SECRET || 'sk-production-secret';
export const JWT_REFRESH_SECRET = process.env.JWT_REFRESH_SECRET || 'sk-production-refresh-secret';

// Development modunda JWT_SECRET'ı logla (güvenlik için production'da loglanmaz)
if (process.env.NODE_ENV === 'development') {
  logger.info('JWT_SECRET configured', { status: JWT_SECRET ? 'Yes (length: ' + JWT_SECRET.length + ')' : 'No (using default)' });
  logger.info('JWT_SECRET value (first 10 chars)', { value: JWT_SECRET.substring(0, 10) + '...' });
}

export const createTokenHash = (token: string): string => {
  return crypto.createHash('sha256').update(token).digest('hex');
};

export const generateTokenPair = (user: IUser): TokenPair => {
  const payload: AccessTokenPayload = {
    id: user._id.toString(),
    email: user.email,
    role: user.role,
  };

  const accessToken = jwt.sign(payload, JWT_SECRET, { expiresIn: '1h' });
  const refreshToken = jwt.sign({ id: user._id.toString() }, JWT_REFRESH_SECRET, { expiresIn: '7d' });

  return { accessToken, refreshToken };
};

export const isMobileClient = (req: { headers?: Record<string, any> }): boolean => {
  const raw =
    (req.headers?.['x-client'] as string | undefined) ||
    (req.headers?.['x-client-platform'] as string | undefined) ||
    '';
  const value = raw.toLowerCase().trim();
  return value === 'mobile' || value === 'expo' || value === 'react-native';
};

import { getRedisClient } from '../config/redis';
import logger from './logger';

export interface CacheOptions {
  ttl?: number; // Time to live in seconds (default: 300 = 5 minutes)
  keyPrefix?: string; // Cache key prefix
}

/**
 * Cache'den veri getir
 */
export const getCache = async <T>(key: string): Promise<T | null> => {
  try {
    const client = getRedisClient();
    if (!client) {
      return null; // Redis yoksa null döndür
    }

    // Client'ın açık olup olmadığını kontrol et
    if (!client.isOpen) {
      return null; // Client kapalıysa null döndür
    }

    const cached = await client.get(key);
    if (cached) {
      return JSON.parse(cached) as T;
    }
    return null;
  } catch (error: any) {
    // "The client is closed" hatasını sessizce handle et
    if (error?.message?.includes('closed') || error?.code === 'ECONNREFUSED') {
      return null; // Redis kapalıysa null döndür, hata loglama
    }
    logger.error(`Cache get error for key ${key}:`, error);
    return null;
  }
};

/**
 * Cache'e veri kaydet
 */
export const setCache = async (
  key: string,
  value: any,
  ttl: number = 300
): Promise<boolean> => {
  try {
    const client = getRedisClient();
    if (!client) {
      return false; // Redis yoksa false döndür
    }

    // Client'ın açık olup olmadığını kontrol et
    if (!client.isOpen) {
      return false; // Client kapalıysa false döndür
    }

    const serialized = JSON.stringify(value);
    await client.setEx(key, ttl, serialized);
    return true;
  } catch (error: any) {
    // "The client is closed" hatasını sessizce handle et
    if (error?.message?.includes('closed') || error?.code === 'ECONNREFUSED') {
      return false; // Redis kapalıysa false döndür, hata loglama
    }
    logger.error(`Cache set error for key ${key}:`, error);
    return false;
  }
};

/**
 * Cache'den veri sil
 */
export const deleteCache = async (key: string): Promise<boolean> => {
  try {
    const client = getRedisClient();
    if (!client || !client.isOpen) {
      return false;
    }

    await client.del(key);
    return true;
  } catch (error: any) {
    if (error?.message?.includes('closed') || error?.code === 'ECONNREFUSED') {
      return false;
    }
    logger.error(`Cache delete error for key ${key}:`, error);
    return false;
  }
};

/**
 * Pattern'e göre cache'leri sil (örnek: "equipment:*")
 */
export const deleteCachePattern = async (pattern: string): Promise<boolean> => {
  try {
    const client = getRedisClient();
    if (!client || !client.isOpen) {
      return false;
    }

    const keys = await client.keys(pattern);
    if (keys.length > 0) {
      await client.del(keys);
    }
    return true;
  } catch (error: any) {
    if (error?.message?.includes('closed') || error?.code === 'ECONNREFUSED') {
      return false;
    }
    logger.error(`Cache delete pattern error for ${pattern}:`, error);
    return false;
  }
};

/**
 * Cache key oluştur
 */
export const createCacheKey = (
  prefix: string,
  ...parts: (string | number | undefined)[]
): string => {
  const validParts = parts.filter((part) => part !== undefined && part !== null);
  return `${prefix}:${validParts.join(':')}`;
};

/**
 * Cache'i temizle (tüm cache'i sil)
 */
export const clearCache = async (): Promise<boolean> => {
  try {
    const client = getRedisClient();
    if (!client || !client.isOpen) {
      return false;
    }

    await client.flushDb();
    return true;
  } catch (error: any) {
    if (error?.message?.includes('closed') || error?.code === 'ECONNREFUSED') {
      return false;
    }
    logger.error('Cache clear error:', error);
    return false;
  }
};

/**
 * Cache istatistikleri
 */
export const getCacheStats = async (): Promise<{
  connected: boolean;
  keys?: number;
}> => {
  try {
    const client = getRedisClient();
    if (!client || !client.isOpen) {
      return { connected: false };
    }

    await client.info('keyspace');
    const keys = await client.dbSize();

    return {
      connected: true,
      keys,
    };
  } catch (error: any) {
    if (error?.message?.includes('closed') || error?.code === 'ECONNREFUSED') {
      return { connected: false };
    }
    logger.error('Cache stats error:', error);
    return { connected: false };
  }
};

import EmailTemplate from '../models/EmailTemplate';
import logger from './logger';

type RenderInput = {
  key: string;
  locale?: string;
  variantName?: string;
  data?: Record<string, any>;
};

type RenderOutput = {
  subject: string;
  html: string;
  used: {
    templateKey: string;
    variantName: string;
    locale: string;
  };
};

const escapeHtml = (value: any): string => {
  const str = value === null || value === undefined ? '' : String(value);
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
};

const getByPath = (obj: any, path: string): any => {
  if (!obj || typeof obj !== 'object') return undefined;
  const parts = path.split('.').filter(Boolean);
  let cur: any = obj;
  for (const p of parts) {
    if (cur && typeof cur === 'object' && p in cur) {
      cur = cur[p];
    } else {
      return undefined;
    }
  }
  return cur;
};

const pickVariant = (variants: Array<{ name: string; weight?: number }>, variantName?: string) => {
  if (variantName) {
    const found = variants.find((v) => v.name === variantName);
    if (found) return found.name;
  }
  const normalized = variants.map((v) => ({ name: v.name, weight: typeof v.weight === 'number' ? v.weight : 100 }));
  const total = normalized.reduce((sum, v) => sum + Math.max(0, v.weight), 0);
  if (total <= 0) return normalized[0]?.name;
  const r = Math.random() * total;
  let acc = 0;
  for (const v of normalized) {
    acc += Math.max(0, v.weight);
    if (r <= acc) return v.name;
  }
  return normalized[0]?.name;
};

const pickLocale = (locales: string[], locale?: string) => {
  if (locale && locales.includes(locale)) return locale;
  if (locales.includes('tr')) return 'tr';
  return locales[0] || 'tr';
};

export const renderInlineTemplate = (
  input: { subject: string; html: string },
  data: Record<string, any>
): { subject: string; html: string } => {
  const render = (tmpl: string) => {
    // {{{var}}} raw
    const withRaw = tmpl.replace(/{{{\s*([\w.]+)\s*}}}/g, (_m, key) => {
      const val = getByPath(data, key);
      return val === null || val === undefined ? '' : String(val);
    });
    // {{var}} escaped
    return withRaw.replace(/{{\s*([\w.]+)\s*}}/g, (_m, key) => {
      const val = getByPath(data, key);
      return escapeHtml(val);
    });
  };
  return {
    subject: render(input.subject),
    html: render(input.html),
  };
};

export const renderEmailTemplate = async (input: RenderInput): Promise<RenderOutput | null> => {
  const templateKey = input.key.trim();
  if (!templateKey) return null;

  try {
    const template = await EmailTemplate.findOne({ key: templateKey, enabled: true }).lean();
    if (!template) return null;
    if (!Array.isArray(template.variants) || template.variants.length === 0) return null;

    const chosenVariantName = pickVariant(template.variants, input.variantName);
    const variant = template.variants.find((v: any) => v.name === chosenVariantName) || template.variants[0];
    const localeKeys = variant?.locales ? Object.keys(variant.locales) : [];
    const chosenLocale = pickLocale(localeKeys, input.locale);

    const localized = (variant.locales && variant.locales[chosenLocale]) || (variant.locales && variant.locales['tr']) || variant.locales?.[localeKeys[0]];
    if (!localized || !localized.subject || !localized.html) return null;

    const data = input.data || {};
    const rendered = renderInlineTemplate({ subject: localized.subject, html: localized.html }, data);

    return {
      subject: rendered.subject,
      html: rendered.html,
      used: {
        templateKey,
        variantName: variant.name,
        locale: chosenLocale,
      },
    };
  } catch (e) {
    logger.error('Email template render hatası', e);
    return null;
  }
};

/**
 * Image Optimization Utility
 * Resimleri optimize eder, boyutlandırır, sıkıştırır
 */

import fs from 'fs';
import path from 'path';
import logger from './logger';

/**
 * Image optimization options
 */
export interface ImageOptimizeOptions {
  maxWidth?: number;
  maxHeight?: number;
  quality?: number; // 1-100
  format?: 'jpeg' | 'png' | 'webp';
}

/**
 * Resim optimizasyonu yapar
 * Sharp kütüphanesi ile resmi boyutlandırır, sıkıştırır ve format dönüştürür
 * Not: Sharp kütüphanesi gerekli (opsiyonel, production'da kullanılabilir)
 * 
 * @param filePath - Optimize edilecek dosya yolu
 * @param options - Optimizasyon seçenekleri
 * @param options.maxWidth - Maksimum genişlik (px, default: 1920)
 * @param options.maxHeight - Maksimum yükseklik (px, default: 1080)
 * @param options.quality - Kalite (1-100, default: 85)
 * @param options.format - Çıktı formatı (jpeg, png, webp, default: jpeg)
 * @returns Optimize edilmiş dosya yolu (orijinal dosya üzerine yazılır)
 * @example
 * await optimizeImage('/uploads/image.jpg', { maxWidth: 1920, quality: 85 });
 */
export const optimizeImage = async (
  filePath: string,
  options: ImageOptimizeOptions = {}
): Promise<string> => {
  const {
    maxWidth = 1920,
    maxHeight = 1080,
    quality = 85,
    format = 'jpeg',
  } = options;

  try {
    // Sharp kontrolü (opsiyonel)
    let sharp: any;
    try {
      sharp = require('sharp');
    } catch (error) {
      logger.warn('Sharp kütüphanesi yüklü değil, resim optimizasyonu atlanıyor');
      return filePath; // Sharp yoksa orijinal dosyayı döndür
    }

    if (!fs.existsSync(filePath)) {
      throw new Error(`Dosya bulunamadı: ${filePath}`);
    }

    const ext = path.extname(filePath).toLowerCase();
    const isImage = ['.jpg', '.jpeg', '.png', '.webp', '.gif'].includes(ext);

    if (!isImage) {
      return filePath; // Resim değilse optimize etme
    }

    // Dosya boyutunu kontrol et
    const stats = fs.statSync(filePath);
    const fileSizeMB = stats.size / (1024 * 1024);

    // Küçük dosyalar için optimize etme (1MB altı)
    if (fileSizeMB < 1) {
      logger.debug(`Dosya zaten küçük (${fileSizeMB.toFixed(2)}MB), optimize edilmedi: ${filePath}`);
      return filePath;
    }

    // Optimize edilmiş dosya yolu
    const optimizedPath = filePath.replace(/(\.[^.]+)$/, `-optimized.${format}`);

    // Sharp ile optimize et
    await sharp(filePath)
      .resize(maxWidth, maxHeight, {
        fit: 'inside',
        withoutEnlargement: true,
      })
      .toFormat(format, { quality })
      .toFile(optimizedPath);

    // Orijinal dosyayı sil ve optimize edilmiş dosyayı orijinal isimle değiştir
    const originalSize = stats.size;
    const optimizedStats = fs.statSync(optimizedPath);
    const optimizedSize = optimizedStats.size;

    const savedMB = (originalSize - optimizedSize) / (1024 * 1024);
    const savedPercent = ((originalSize - optimizedSize) / originalSize) * 100;

    logger.info(
      `Resim optimize edildi: ${path.basename(filePath)} - ${savedMB.toFixed(2)}MB tasarruf (%${savedPercent.toFixed(1)})`
    );

    // Orijinal dosyayı sil ve optimize edilmiş dosyayı orijinal isimle değiştir
    fs.unlinkSync(filePath);
    fs.renameSync(optimizedPath, filePath);

    return filePath;
  } catch (error) {
    logger.error(`Resim optimizasyonu hatası: ${filePath}`, error);
    return filePath; // Hata durumunda orijinal dosyayı döndür
  }
};

/**
 * Resim boyutunu kontrol eder ve gerekirse optimize eder
 * Dosya boyutu belirtilen MB'dan büyükse otomatik optimize eder
 * 
 * @param filePath - Kontrol edilecek dosya yolu
 * @param maxSizeMB - Maksimum dosya boyutu (MB, default: 5)
 * @returns Optimize edilmiş dosya yolu
 * @example
 * await checkAndOptimizeImage('/uploads/image.jpg', 5); // 5MB'dan büyükse optimize et
 */
export const checkAndOptimizeImage = async (
  filePath: string,
  maxSizeMB: number = 5
): Promise<string> => {
  try {
    if (!fs.existsSync(filePath)) {
      return filePath;
    }

    const stats = fs.statSync(filePath);
    const fileSizeMB = stats.size / (1024 * 1024);

    if (fileSizeMB > maxSizeMB) {
      logger.info(`Büyük resim bulundu (${fileSizeMB.toFixed(2)}MB), optimize ediliyor: ${filePath}`);
      return await optimizeImage(filePath);
    }

    return filePath;
  } catch (error) {
    logger.error(`Resim kontrolü hatası: ${filePath}`, error);
    return filePath;
  }
};

/**
 * Batch image optimization
 * Birden fazla resmi toplu olarak optimize eder
 * @param filePaths - Optimize edilecek dosya yolları dizisi
 * @param options - Optimizasyon seçenekleri
 * @returns Optimizasyon sonuçları (optimized, skipped, errors)
 * @example
 * const result = await optimizeImages(['/uploads/img1.jpg', '/uploads/img2.jpg']);
 * console.log(`${result.optimized} resim optimize edildi`);
 */
export const optimizeImages = async (
  filePaths: string[],
  options: ImageOptimizeOptions = {}
): Promise<{ optimized: number; skipped: number; errors: number }> => {
  let optimized = 0;
  let skipped = 0;
  let errors = 0;

  for (const filePath of filePaths) {
    try {
      const result = await optimizeImage(filePath, options);
      if (result !== filePath) {
        optimized++;
      } else {
        skipped++;
      }
    } catch (error) {
      errors++;
      logger.error(`Batch optimize hatası: ${filePath}`, error);
    }
  }

  return { optimized, skipped, errors };
};

/**
 * Log Transports
 * Winston transport konfigürasyonları (ELK, CloudWatch, vb.)
 */

import winston from 'winston';
import logger from './logger';

/**
 * CloudWatch Logs Transport
 * AWS CloudWatch Logs'a log gönderir
 */
export const createCloudWatchTransport = (): winston.transport | null => {
  try {
    // CloudWatch Logs sadece production'da ve AWS credentials varsa aktif
    if (process.env.NODE_ENV !== 'production' || !process.env.AWS_REGION) {
      return null;
    }

    // winston-cloudwatch paketi type tanımları eksik olabilir
    const CloudWatchTransport = require('winston-cloudwatch');

    return new CloudWatchTransport({
      logGroupName: process.env.CLOUDWATCH_LOG_GROUP || 'sk-production-api',
      logStreamName: process.env.CLOUDWATCH_LOG_STREAM || `${process.env.NODE_ENV}-${new Date().toISOString().split('T')[0]}`,
      awsRegion: process.env.AWS_REGION,
      awsAccessKeyId: process.env.AWS_ACCESS_KEY_ID,
      awsSecretKey: process.env.AWS_SECRET_ACCESS_KEY,
      messageFormatter: (info: any) => {
        return JSON.stringify({
          level: info.level,
          message: info.message,
          timestamp: info.timestamp,
          ...info.metadata,
        });
      },
      jsonMessage: true,
    });
  } catch (error) {
    logger.warn('CloudWatch transport oluşturulamadı:', error);
    return null;
  }
};

/**
 * Elasticsearch Transport
 * ELK stack'e log gönderir
 * 
 * NOT: winston-elasticsearch paketi opsiyonel dependency'dir
 * Kullanmak için: npm install winston-elasticsearch --save
 */
export const createElasticsearchTransport = (): winston.transport | null => {
  try {
    // Elasticsearch sadece production'da ve ELASTICSEARCH_URL varsa aktif
    if (process.env.NODE_ENV !== 'production' || !process.env.ELASTICSEARCH_URL || process.env.ENABLE_ELASTICSEARCH_LOGS !== 'true') {
      return null;
    }

    // winston-elasticsearch paketi yüklü mü kontrol et
    let ElasticsearchTransport;
    try {
      ElasticsearchTransport = require('winston-elasticsearch');
    } catch (error) {
      logger.warn('winston-elasticsearch paketi bulunamadı. Elasticsearch transport devre dışı. Yüklemek için: npm install winston-elasticsearch --save');
      return null;
    }

    // winston-elasticsearch paketi type tanımları eksik olabilir
    return new ElasticsearchTransport({
      level: process.env.LOG_LEVEL || 'info',
      clientOpts: {
        node: process.env.ELASTICSEARCH_URL,
        auth: process.env.ELASTICSEARCH_USERNAME && process.env.ELASTICSEARCH_PASSWORD ? {
          username: process.env.ELASTICSEARCH_USERNAME,
          password: process.env.ELASTICSEARCH_PASSWORD,
        } : undefined,
      },
      index: process.env.ELASTICSEARCH_INDEX || 'sk-production-logs',
      indexTemplate: {
        index_patterns: [process.env.ELASTICSEARCH_INDEX || 'sk-production-logs'],
        settings: {
          number_of_shards: 1,
          number_of_replicas: 0,
        },
        mappings: {
          properties: {
            timestamp: { type: 'date' },
            level: { type: 'keyword' },
            message: { type: 'text' },
            service: { type: 'keyword' },
            requestId: { type: 'keyword' },
          },
        },
      },
      transformer: (logData: any) => {
        return {
          '@timestamp': logData.timestamp || new Date().toISOString(),
          level: logData.level,
          message: logData.message,
          service: logData.metadata?.service || 'sk-production-api',
          requestId: logData.metadata?.requestId,
          ...logData.metadata,
        };
      },
    });
  } catch (error) {
    logger.warn('Elasticsearch transport oluşturulamadı:', error);
    return null;
  }
};

/**
 * File Transport (JSON format)
 * Log dosyalarına JSON formatında yazar (log aggregation için)
 */
export const createFileTransport = (): winston.transport | null => {
  try {
    const logDir = process.env.LOG_DIR || 'logs';
    const fs = require('fs');
    const path = require('path');

    // Log klasörünü oluştur
    if (!fs.existsSync(logDir)) {
      fs.mkdirSync(logDir, { recursive: true });
    }

    return new winston.transports.File({
      filename: path.join(logDir, 'app.json'),
      format: winston.format.json(),
      maxsize: 10 * 1024 * 1024, // 10MB
      maxFiles: 5,
      tailable: true,
    });
  } catch (error) {
    logger.warn('File transport oluşturulamadı:', error);
    return null;
  }
};

/**
 * Tüm log transport'larını oluştur
 * Environment variable'lara göre aktif transport'ları döndürür
 */
export const createLogTransports = (): winston.transport[] => {
  const transports: winston.transport[] = [];

  // Console transport (her zaman aktif)
  transports.push(
    new winston.transports.Console({
      format: process.env.LOG_CONSOLE_FORMAT === 'json'
        ? winston.format.json()
        : winston.format.combine(
          winston.format.colorize(),
          winston.format.simple()
        ),
    })
  );

  // File transport (JSON format)
  const fileTransport = createFileTransport();
  if (fileTransport) {
    transports.push(fileTransport);
  }

  // CloudWatch transport (production + AWS credentials varsa)
  if (process.env.ENABLE_CLOUDWATCH_LOGS === 'true') {
    const cloudWatchTransport = createCloudWatchTransport();
    if (cloudWatchTransport) {
      transports.push(cloudWatchTransport);
    }
  }

  // Elasticsearch transport (production + ELASTICSEARCH_URL varsa)
  if (process.env.ENABLE_ELASTICSEARCH_LOGS === 'true') {
    const elasticsearchTransport = createElasticsearchTransport();
    if (elasticsearchTransport) {
      transports.push(elasticsearchTransport);
    }
  }

  return transports;
};

/**
 * Server-side Logger Utility
 * Winston kullanarak structured logging sağlar
 * Production'da dosyaya, development'ta console'a yazar
 */

import winston from 'winston';
import path from 'path';
import { getRequestId } from './requestContext';
import fs from 'fs';
import { createCloudWatchTransport, createElasticsearchTransport } from './logTransports';

const isProd = process.env.NODE_ENV === 'production';

const ensureLogsDir = () => {
  const logsDir = path.join(process.cwd(), 'logs');
  if (!fs.existsSync(logsDir)) {
    fs.mkdirSync(logsDir, { recursive: true });
  }
  return logsDir;
};

/**
 * Log formatı (JSON formatında structured logging)
 */
const logFormat = winston.format.combine(
  winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
  winston.format.errors({ stack: true }),
  winston.format.splat(),
  winston.format((info) => {
    const rid = getRequestId();
    if (rid) {
      (info as any).requestId = rid;
    }
    return info;
  })(),
  winston.format.json()
);

/**
 * Console formatı (development için)
 * Renkli ve okunabilir format
 */
const consoleFormat = winston.format.combine(
  winston.format.colorize(),
  winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
  winston.format.printf(({ timestamp, level, message, ...meta }) => {
    const requestId = (meta as any).requestId ? ` rid=${(meta as any).requestId}` : '';
    // requestId'yi meta içinden çıkartıp tekrar yazdırmayalım
    if ((meta as any).requestId) delete (meta as any).requestId;
    let msg = `${timestamp} [${level}]${requestId}: ${message}`;
    if (Object.keys(meta).length > 0) {
      msg += ` ${JSON.stringify(meta)}`;
    }
    return msg;
  })
);

/**
 * Winston logger instance
 * - Error logları: logs/error.log
 * - Tüm loglar: logs/combined.log
 * - Development: Console'a da yazar
 * - Production: Sadece warn ve error console'a yazar
 */
const consoleTransportFormat = process.env.LOG_CONSOLE_FORMAT === 'json' ? logFormat : consoleFormat;

const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: logFormat,
  defaultMeta: { service: 'sk-production-api' },
  transports: [
    // Hata logları için ayrı dosya
    new winston.transports.File({
      filename: path.join(ensureLogsDir(), 'error.log'),
      level: 'error',
      maxsize: 5242880, // 5MB
      maxFiles: 5,
    }),
    // Tüm loglar için dosya
    new winston.transports.File({
      filename: path.join(ensureLogsDir(), 'combined.log'),
      maxsize: 5242880, // 5MB
      maxFiles: 5,
    }),
  ],
});

// Development ortamında console'a da yazdır
if (!isProd) {
  logger.add(
    new winston.transports.Console({
      format: consoleTransportFormat,
    })
  );
}

// Production'da stdout/stderr üzerinden log aggregation daha sağlıklı.
// Default: info ve üzeri; LOG_LEVEL ile değiştirilebilir.
if (isProd) {
  logger.add(
    new winston.transports.Console({
      format: consoleTransportFormat,
      level: process.env.LOG_LEVEL || 'info',
    })
  );

  // CloudWatch transport ekle (production + AWS credentials varsa)
  const cloudWatchTransport = createCloudWatchTransport();
  if (cloudWatchTransport) {
    logger.add(cloudWatchTransport);
  }

  // Elasticsearch transport ekle (production + ELASTICSEARCH_URL varsa)
  const elasticsearchTransport = createElasticsearchTransport();
  if (elasticsearchTransport) {
    logger.add(elasticsearchTransport);
  }
}

export default logger;

import mongoose from 'mongoose';
import { recordDbMetric } from './monitoringStore';

let isInitialized = false;

export const initMongooseQueryMonitor = () => {
  if (isInitialized) return;
  isInitialized = true;

  const Query: any = (mongoose as any).Query;
  if (!Query || !Query.prototype || typeof Query.prototype.exec !== 'function') return;

  const originalExec = Query.prototype.exec;

  Query.prototype.exec = async function patchedExec(this: any, ...args: any[]) {
    const start = process.hrtime.bigint();
    try {
      // eslint-disable-next-line prefer-rest-params
      return await originalExec.apply(this, args);
    } finally {
      const end = process.hrtime.bigint();
      const durationMs = Number(end - start) / 1_000_000;
      const model = this?.model?.modelName || 'Unknown';
      const operation = this?.op || 'unknown';
      recordDbMetric({
        ts: Date.now(),
        model,
        operation,
        durationMs,
      });
    }
  };
};

import { Notification, User, NotificationSettings } from '../models';
import { sendEmail } from './emailService';
import logger from './logger';
import mongoose from 'mongoose';
import { sendPushNotification } from './pushNotificationService';
import { sendToUser } from './realtime/realtimeHub';

export interface CreateNotificationParams {
  userId: mongoose.Types.ObjectId | string;
  type: 'TASK_ASSIGNED' | 'TASK_UPDATED' | 'PROJECT_STARTED' | 'PROJECT_UPDATED' | 'PROJECT_COMPLETED' | 'MAINTENANCE_REMINDER' | 'MAINTENANCE_DUE' | 'EQUIPMENT_ASSIGNED' | 'USER_INVITED' | 'SYSTEM';
  title: string;
  message: string;
  data?: any;
  sendEmail?: boolean;
  emailSubject?: string;
}

// Bildirim oluştur ve gönder
export const createNotification = async (params: CreateNotificationParams): Promise<any> => {
  try {
    const notification = await Notification.create({
      userId: params.userId,
      type: params.type,
      title: params.title,
      message: params.message,
      data: params.data || {},
      read: false,
    });

    // Real-time (SSE) bildirim (web/panel için)
    try {
      sendToUser(String(params.userId), 'notification:new', {
        _id: notification._id?.toString?.() || undefined,
        userId: String(params.userId),
        type: params.type,
        title: params.title,
        message: params.message,
        data: params.data || {},
        createdAt: (notification as any)?.createdAt || new Date().toISOString(),
      });
    } catch {
      // realtime hatası bildirimi engellemez
    }

    // Push notification gönder (kullanıcı ayarlarına göre)
    try {
      const settings = await NotificationSettings.findOne({ userId: params.userId });

      // Kullanıcı push notification'ları aktif etmişse ve bu tip için izin vermişse gönder
      if (
        (!settings || settings.pushEnabled) &&
        (!settings || !settings.pushTypes || settings.pushTypes[params.type] !== false)
      ) {
        await sendPushNotification(String(params.userId), {
          title: params.title,
          body: params.message,
          data: {
            notificationId: notification._id.toString(),
            type: params.type,
            ...params.data,
          },
          tag: params.type,
          requireInteraction: params.type === 'MAINTENANCE_DUE' || params.type === 'TASK_ASSIGNED',
          actions: [
            {
              action: 'view',
              title: 'Görüntüle',
            },
            {
              action: 'dismiss',
              title: 'Kapat',
            },
          ],
        });
      }
    } catch (pushError) {
      logger.error('Push notification gönderme hatası:', pushError);
      // Push hatası bildirimi engellemez
    }

    // Email gönder (kullanıcı ayarlarına göre)
    const shouldSendEmail = params.sendEmail || false;
    if (shouldSendEmail) {
      try {
        const settings = await NotificationSettings.findOne({ userId: params.userId });

        // Kullanıcı email notification'ları aktif etmişse ve bu tip için izin vermişse gönder
        if (
          (!settings || settings.emailEnabled) &&
          (!settings || !settings.emailTypes || settings.emailTypes[params.type] !== false)
        ) {
          const user = await User.findById(params.userId);
          if (user && user.email) {
          const emailHtml = `
            <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
              <h2 style="color: #0066CC;">${params.title}</h2>
              <p>${params.message}</p>
              <p style="margin-top: 20px;">
                <a href="${process.env.FRONTEND_URL || 'http://localhost:3000'}/admin/notifications" 
                   style="background-color: #0066CC; color: white; padding: 12px 24px; text-decoration: none; border-radius: 5px; display: inline-block;">
                  Bildirimleri Görüntüle
                </a>
              </p>
              <p>İyi çalışmalar,<br>SK Production</p>
            </div>
          `;

          await sendEmail(
            user.email,
            params.emailSubject || params.title,
            emailHtml
          );
          }
        }
      } catch (emailError) {
        logger.error('Bildirim email gönderme hatası:', emailError);
        // Email hatası bildirimi engellemez
      }
    }

    return notification;
  } catch (error) {
    logger.error('Bildirim oluşturma hatası:', error);
    throw error;
  }
};

// Kullanıcıya bildirim gönder
export const notifyUser = async (
  userId: mongoose.Types.ObjectId | string,
  type: CreateNotificationParams['type'],
  title: string,
  message: string,
  data?: any,
  sendEmail = false
): Promise<any> => {
  return createNotification({
    userId,
    type,
    title,
    message,
    data,
    sendEmail,
  });
};

// Çoklu kullanıcıya bildirim gönder
export const notifyUsers = async (
  userIds: (mongoose.Types.ObjectId | string)[],
  type: CreateNotificationParams['type'],
  title: string,
  message: string,
  data?: any,
  sendEmail = false
): Promise<any[]> => {
  const notifications = await Promise.all(
    userIds.map(userId =>
      createNotification({
        userId,
        type,
        title,
        message,
        data,
        sendEmail,
      })
    )
  );

  return notifications;
};

// Proje ekibine bildirim gönder
export const notifyProjectTeam = async (
  teamMemberIds: (mongoose.Types.ObjectId | string)[],
  type: CreateNotificationParams['type'],
  title: string,
  message: string,
  projectId?: string,
  sendEmail = false
): Promise<any[]> => {
  return notifyUsers(
    teamMemberIds,
    type,
    title,
    message,
    { projectId },
    sendEmail
  );
};

import webpush from 'web-push';
import PushSubscription from '../models/PushSubscription';
import logger from './logger';

let vapidConfigured = false;
let vapidMissingLogged = false;

const ensureVapidConfigured = (): boolean => {
  const VAPID_PUBLIC_KEY = process.env.VAPID_PUBLIC_KEY;
  const VAPID_PRIVATE_KEY = process.env.VAPID_PRIVATE_KEY;
  const VAPID_SUBJECT = process.env.VAPID_SUBJECT || 'mailto:info@skpro.com.tr';
  const isProd = process.env.NODE_ENV === 'production';

  if (!VAPID_PUBLIC_KEY || !VAPID_PRIVATE_KEY) {
    if (!vapidMissingLogged) {
      vapidMissingLogged = true;
      // Dev ortamında push opsiyonel: warn yerine info (log gürültüsünü azalt).
      const msg = 'VAPID keys ayarlanmamış. Push notification gönderilemeyecek.';
      if (isProd) logger.warn(msg);
      else logger.info(msg);
    }
    return false;
  }

  if (!vapidConfigured) {
    webpush.setVapidDetails(VAPID_SUBJECT, VAPID_PUBLIC_KEY, VAPID_PRIVATE_KEY);
    vapidConfigured = true;
  }

  return true;
};

export interface PushNotificationPayload {
  title: string;
  body: string;
  icon?: string;
  badge?: string;
  data?: any;
  tag?: string;
  requireInteraction?: boolean;
  actions?: Array<{
    action: string;
    title: string;
    icon?: string;
  }>;
}

/**
 * Kullanıcıya push notification gönder
 */
export const sendPushNotification = async (
  userId: string,
  payload: PushNotificationPayload
): Promise<boolean> => {
  try {
    if (!ensureVapidConfigured()) {
      return false;
    }

    // Kullanıcının tüm subscription'larını al
    const subscriptions = await PushSubscription.find({ userId });

    if (subscriptions.length === 0) {
      logger.debug(`Kullanıcı ${userId} için push subscription bulunamadı`);
      return false;
    }

    const notificationPayload = JSON.stringify({
      title: payload.title,
      body: payload.body,
      icon: payload.icon || '/images/sk-logo.png',
      badge: payload.badge || '/images/sk-logo.png',
      data: payload.data || {},
      tag: payload.tag,
      requireInteraction: payload.requireInteraction || false,
      actions: payload.actions || [],
    });

    // Tüm subscription'lara gönder
    const results = await Promise.allSettled(
      subscriptions.map(async (subscription) => {
        try {
          await webpush.sendNotification(
            {
              endpoint: subscription.endpoint,
              keys: {
                p256dh: subscription.keys.p256dh,
                auth: subscription.keys.auth,
              },
            },
            notificationPayload
          );
          return true;
        } catch (error: any) {
          // Subscription geçersizse sil
          if (error.statusCode === 410 || error.statusCode === 404) {
            logger.info(`Geçersiz subscription siliniyor: ${subscription._id}`);
            await PushSubscription.findByIdAndDelete(subscription._id);
          } else {
            logger.error(`Push notification gönderme hatası:`, error);
          }
          return false;
        }
      })
    );

    const successCount = results.filter((r) => r.status === 'fulfilled' && r.value === true).length;
    logger.info(`Push notification gönderildi: ${successCount}/${subscriptions.length} başarılı`);

    return successCount > 0;
  } catch (error) {
    logger.error('Push notification gönderme hatası:', error);
    return false;
  }
};

/**
 * Çoklu kullanıcıya push notification gönder
 */
export const sendPushNotificationToUsers = async (
  userIds: string[],
  payload: PushNotificationPayload
): Promise<{ success: number; failed: number }> => {
  const results = await Promise.allSettled(
    userIds.map((userId) => sendPushNotification(userId, payload))
  );

  const success = results.filter((r) => r.status === 'fulfilled' && r.value === true).length;
  const failed = results.length - success;

  return { success, failed };
};

